def make_dataset_blob_config_mmb20() -> dict:
    """
    Dataset-blob build config for the cross-platform retrieval dataset
    (`/lustre/.../silver/mmb0-1b_smb1-20b_1p_shared_genes`, 21 AnnDatas:
    1 MERFISH mouse-brain section + 20 STARmap+ mouse-CNS sections, all
    reindexed to the MERFISH gene panel via examples/harmonize_mmb_smb20_panels.py).

    Run order (one-time):
        1. python examples/harmonize_mmb_smb20_panels.py
           -> writes harmonised AnnDatas to <DATA_ROOT>/silver/<dataset>_shared_genes/
        2. python examples/run_squint.py --build-blob --build-blob-dataset mmb20
           -> reads from the dir written in step 1, builds dataset_blob.pt

    Notes:
      - root data path -> /lustre/scratch126/cellgen/lotfollahi/DATASETS
        (where the original mmb0-1b_smb1-20b_1p folder lives).
      - dataset name  -> mmb0-1b_smb1-20b_1p_shared_genes (matches the
        output dir of harmonize_mmb_smb20_panels.py).
      - label_names empty: STARmap obs columns vary (some have
        Sub_molecular_tissue_region, others may have cell_type only); the
        blob loader is defensive and skips missing label columns. The
        per-cell labels are still propagated to inference via
        `obs_per_batch_id` (we now carry the full obs DataFrames) — no
        need to register them as supervised y_* tensors here.
      - graph_kwargs.batch_key -> 'batch'. The harmonize script stamps
        every AnnData with obs['batch'] = 'batchN', so
        `build_batch_one_hot_from_obs` densifies cleanly.
    """
    return {
        "experiment": {
            "name": "in_memory_dataset_blob",
            "description": (
                "MERFISH mouse-brain (1 section) + STARmap+ mouse-CNS "
                "(20 sections) on the shared MERFISH gene panel."
            ),
        },
        "dataset": {
            "name": "mmb0-1b_smb1-20b_1p_shared_genes",
            "feature_names": ["cell_gene_counts"],
            "label_names": [],
            "graph_kwargs": {
                "coord_type":         "generic",
                "spatial_key":        "spatial",
                # k=8 (smoke test) + k=16 (the s49_v23 spine uses
                # graph_knn(n_neighs=16)); both spatial graphs are
                # precomputed so either sampler depth is available
                # without a rebuild.
                "n_neighs_list":      [8, 16],
                "radius_list":        None,
                "include_self_loop":  True,
                "batch_key":          "batch",
                "k": {
                    "lm_eigvecs": 128,
                },
            },
            "data_directory_path": str(DATA_ROOT),
            "pre_transform": None,
            "pre_filter":    None,
            "overwrite":     True,
        },
        "software_paths": {
            "deepwalk": "",
            "gosh":     "",
        },
    }


def make_dataset_blob_config_mmb239() -> dict:
    """
    Dataset-blob build config for the 239-section MERFISH mouse-brain
    dataset (`/lustre/.../silver/mmb0-239b_1p`, 239 AnnDatas:
    harmonised_merfish_mouse_brain_239-batch_batch{1..239}.h5ad).

    Unlike `make_dataset_blob_config_mmb20` (which mixes MERFISH + STARmap
    and therefore needs panel harmonization -> a `_shared_genes` dir), ALL
    239 sections here are MERFISH mouse brain on the SAME gene panel, so NO
    harmonization step is required: we read the silver dir directly and the
    dataset name has no `_shared_genes` suffix.

    Run order (one-time):
        python examples/run_squint.py --build-blob --build-blob-dataset mmb0-239b_1p
        -> reads /lustre/.../silver/mmb0-239b_1p, builds dataset_blob.pt

    Notes:
      - root data path -> /lustre/scratch126/cellgen/lotfollahi/DATASETS
        (same DATA_ROOT as mmb20; silver/mmb0-239b_1p lives under it).
      - n_neighs_list [8, 16]: 8 = SQUINT default / smoke; 16 = the
        s49_v23 spine (graph_knn(n_neighs=16)). Both precomputed so no
        rebuild per sampler depth.
      - batch_key 'batch': the silver AnnDatas carry obs['batch'] = the
        per-section id, so `build_batch_one_hot_from_obs` densifies cleanly
        across all 239 sections.
      - label_names empty: no supervised heads; per-cell obs is carried to
        inference via `obs_per_batch_id`.
    """
    return {
        "experiment": {
            "name": "in_memory_dataset_blob",
            "description": (
                "MERFISH mouse-brain, 239 sections, single shared gene "
                "panel (no harmonization needed)."
            ),
        },
        "dataset": {
            "name": "mmb0-239b_1p",
            "feature_names": ["cell_gene_counts"],
            "label_names": [],
            "graph_kwargs": {
                "coord_type":         "generic",
                "spatial_key":        "spatial",
                "n_neighs_list":      [8, 16],
                "radius_list":        None,
                "include_self_loop":  True,
                "batch_key":          "batch",
                # NO Laplacian spectral embeddings. The s49_v23 model uses
                # feature_names=["cell_gene_counts"] and never consumes
                # U_lm_eigvecs (0 references in run_squint.py), so computing
                # 128 eigvecs (eigsh, k=128) per graph per section is the
                # dominant, wasted build cost over 239 sections. Skipping it
                # is the single biggest speedup. Re-add {"lm_eigvecs": N} and
                # rebuild only if a future variant needs spectral features.
                "k": {},
            },
            "data_directory_path": str(DATA_ROOT),
            "pre_transform": None,
            "pre_filter":    None,
            "overwrite":     True,
        },
        "software_paths": {
            "deepwalk": "",
            "gosh":     "",
        },
    }


def _make_spatch_blob_config(name: str, description: str,
                             label_names: Optional[List[str]] = None) -> dict:
    """
    Shared body for all `spatch_*_1p` blob configs (and reusable for other
    silver datasets with the same shape). Differs from
    `make_dataset_blob_config_spatch` (the original smoke-test variant)
    in two ways:
      - parameterised by `name` so the same config shape works for
        spatch_1p, spatch_ov_1p, spatch_hcc_1p, spatch_coad_1p, ...
      - n_neighs_list pre-populates k=8, 16, 24 so the s51 ablation
        sweep (which uses all three k values) doesn't require a
        rebuild per knn ablation.

    `label_names` maps SQUINT label tensors to the per-cell obs columns in
    the silver AnnDatas, as "<name>=<obs_column>" (the builder splits on
    '='). Defaults to the spatch convention
    (cell_types=annotation, niche_types=spatial_cluster); pass a custom list
    to register a dataset that keeps its labels under different column names
    (e.g. the tonsil / lymph-node atlases:
    ["cell_types=cell_type_annotation", "niche_types=niche_annotation"]).
    """
    if label_names is None:
        label_names = ["cell_types=annotation", "niche_types=spatial_cluster"]
    return {
        "experiment": {
            "name": "in_memory_dataset_blob",
            "description": description,
        },
        "dataset": {
            "name": name,
            "feature_names": ["cell_gene_counts"],
            "label_names": list(label_names),
            "graph_kwargs": {
                "coord_type":         "generic",
                "spatial_key":        "spatial",
                # 8 = SQUINT default; 16 = knn16 base; 24 = knn24
                # ablation in the s51 sweep. Pre-built so no rebuild
                # per knn variant.
                "n_neighs_list":      [8, 16, 24],
                "radius_list":        None,
                "include_self_loop":  True,
                "batch_key":          "batch",
                "k": {
                    "lm_eigvecs": 128,
                },
            },
            "data_directory_path": "/nfs/team361/sb75/DATASETS",
            "pre_transform": None,
            "pre_filter":    None,
            "overwrite":     True,
        },
        "software_paths": {
            "deepwalk": "",
            "gosh":     "",
        },
    }


def make_dataset_blob_config_spatch_ov() -> dict:
    """Ovarian-cancer spatch subset (`silver/spatch_ov_1p/dataset_id_*.h5ad`)."""
    return _make_spatch_blob_config(
        name="spatch_ov_1p",
        description="spatch_ov_1p — ovarian cancer subset (silver/spatch_ov_1p).",
    )


