def make_dataset_blob_config_spatch() -> dict:
    """
    Dataset-blob build config for the `spatch_1p` dataset
    (`/nfs/team361/sb75/DATASETS/silver/spatch_1p`, N AnnDatas named
    `dataset_id_<N>.h5ad`).

    Smoke-test scope: this config is intended for a 1-epoch pipeline
    sanity check. It uses cell-type label `obs['annotation']` and niche
    label `obs['spatial_cluster']` — the supervisory keys the user
    specified for this dataset.

    Expectations on the silver AnnDatas:
      - `adata.uns['batch']`           — integer / 'batchN' string for
        each section (required by `InMemoryDatasetBlob._derive_adata_batch_id`).
        `dataset_id_<N>.h5ad` should stamp `uns['batch']` so the file's
        intended id surfaces — e.g. `dataset_id_2.h5ad` -> `uns['batch']='batch2'`
        (or just the int `2`). See `examples/stamp_spatch_uns_batch.py`.
      - `adata.obs['annotation']`      — cell-type label column.
      - `adata.obs['spatial_cluster']` — niche / spatial-cluster label.
      - `adata.obsm['spatial']`        — XY coordinates for the spatial
        k-NN graph build.
      - `adata.obs['batch']`           — per-cell batch (used by the
        batch-key path in the blob's graph build + by
        `build_batch_one_hot_from_obs`). If absent, the loader falls
        back to parsing `cell_id`; either is fine for the smoke test.

    Differences from `make_dataset_blob_config`:
      - dataset name -> spatch_1p
      - data_directory_path -> /nfs/team361/sb75/DATASETS
      - label_names         -> ["cell_types=annotation",
                                "niche_types=spatial_cluster"]
      - n_neighs_list       -> [8] (single k for smoke; expand later
        if knn-ablations are added on spatch_1p).
    """
    return {
        "experiment": {
            "name": "in_memory_dataset_blob",
            "description": (
                "spatch_1p dataset (silver/spatch_1p/dataset_id_*.h5ad). "
                "Cell-type label = obs['annotation']; niche label = "
                "obs['spatial_cluster']."
            ),
        },
        "dataset": {
            "name": "spatch_1p",
            "feature_names": ["cell_gene_counts"],
            "label_names": [
                "cell_types=annotation",
                "niche_types=spatial_cluster",
            ],
            "graph_kwargs": {
                "coord_type":         "generic",
                "spatial_key":        "spatial",
                "n_neighs_list":      [8, 16],  # 8 = SQUINT default, 16 = knn16 variants
                "radius_list":        None,
                "include_self_loop":  True,
                "batch_key":          "batch",   # falls back to cell_id parse if absent
                "k": {
                    "lm_eigvecs": 128,
                },
            },
            "data_directory_path": "/nfs/team361/sb75/DATASETS",
            "pre_transform": None,
            "pre_filter":    None,
            "overwrite":     True,
        },
        "software_paths": {
            "deepwalk": "",
            "gosh":     "",
        },
    }


def make_dataset_blob_config() -> dict:
    """
    Mirrors  config/create_in_memory_dataset_blob/mmb0-4b_1p.yaml  but for
    our two-section dataset. We turn off DeepWalk/GOSH (which need extra
    binaries) and only build Laplacian eigenvectors. We also build the 8-NN
    spatial graph that SQUINT uses by default.
    """
    return {
        "experiment": {
            "name": "in_memory_dataset_blob",
            "description": "MERFISH MB batch82 + STARmap+ MB batch15 (shared gene panel, coord aligned)",
        },
        "dataset": {
            "name": DATASET_NAME,
            "feature_names": ["cell_gene_counts"],
            "label_names": [
                "cell_types=cell_type",
                # If your AnnData also has e.g. region labels in obs['region'],
                # add: "niche_types=region"
            ],
            "graph_kwargs": {
                "coord_type": "generic",
                "spatial_key": "spatial",     # adata.obsm['spatial']
                # Build the spatial k-NN graph at MULTIPLE k values so
                # variants can select between them at training time via
                # `cfg.dataset.graph_params.n_neighs`. The default
                # training config picks k=8 (the historic SQUINT
                # default); +knn12 / +knn6 variants select k=12 / k=6
                # from the same pre-built blob. Rebuilding the blob is
                # required ONCE to populate the extra graphs:
                #   python examples/run_squint.py --build-blob
                "n_neighs_list": [6, 8, 12, 16, 20, 24],  # SQUINT default 8-NN + knn ablations
                "radius_list": None,
                "include_self_loop": True,
                "k": {
                    # Spectral embeddings — cheap, optional.
                    "lm_eigvecs": 128,
                    # DeepWalk / GOSH skipped (require external binaries).
                },
            },
            "data_directory_path": str(DATA_ROOT),
            "pre_transform": None,
            "pre_filter": None,
            "overwrite": True,
        },
        "software_paths": {
            # not used because we omit deepwalk/gosh from k above
            "deepwalk": "",
            "gosh": "",
        },
    }


# ---------------------------------------------------------------------------
# 2a. Training config — minimal POC (Graph VQ-VAE baseline)
# ---------------------------------------------------------------------------

def make_train_config_poc() -> dict:
    """
    Right-sized Graph VQ-VAE baseline for 431-gene / ~100k-cell spatial data.

    Design choices:
    - No HVG subsetting (`apply_hvg=False`): the gene panel is already curated;
      set apply_hvg=True (and adjust n_hvg) for larger multi-panel datasets.
    - Encoder: 431 -> MLP[400,256] -> GNN[128, 1 layer, 8-NN] -> VQ[30 codes].
      Latent dim = 128 keeps the VQ cosine-similarity manifold tractable for
      30 codes.  A 30-code codebook with 400-dim embeddings is over-parametrised
      and slows EMA convergence.
    - Decoder: latent[128] -> MLP[400] -> softmax * read_depth -> NB mean.
    - Adjacency decoder: kept at low capacity (128 -> MLP[64]) to avoid the
      BCE adj loss dominating when it's added.
    - Dropout: removed.  With a 30-code bottleneck the model has limited spare
      capacity and dropout further destabilises VQ code assignment.
    - Sampler: 1 hop, 8 neighbors — matches GNN num_layers=1.  Sampling 2 hops
      for a 1-layer GNN is wasted compute.
    - LR: 5e-4 (conservative; 1e-3 tends to cause sharp loss spikes on VQ init).
    - Batch: 256.  ~100k cells -> ~390 batches/epoch, sufficient gradient
      diversity for EMA codebook updates.
    - Epochs: 80.  EMA VQ needs ~40-60 epochs to stabilise dead-code rate.
    - Metrics: pearson_gene_wise_log1p is the primary checkpoint signal.
      It is the metric reported by scVI-tools, NicheCompass, and spatial-
      imputation papers (Tangram, SpaGE, STAGATE).  Per-gene Pearson on
      log1p(counts) assigns equal weight to all genes and is insensitive to
      the mean-count dominance that makes raw-count cell-wise Pearson decrease
      early in training.  pearson_cell_wise_log1p and pearson_gene_wise are
      tracked as secondary metrics.

    recon_mode is injected by patch helpers and defaults to 'cell' here.
    """
    return {
        "experiment": {"seed": 0, "mode": "standalone"},
        "logging": {
            "root_log_dir": str(LOG_ROOT),
            # Don't upload checkpoints to wandb. Lightning's
            # ModelCheckpoint already writes the best ckpt to
            # `<run_dir>/checkpoints/` on NFS, which is the canonical
            # location predict() reads from. Wandb upload of large
            # tensors stages each ckpt into $WANDB_CACHE_DIR (default
            # $HOME/.cache/wandb/artifacts/staging/) and across a
            # multi-variant sweep that overflows typical HPC home quotas.
            "log_model": False,
            "offline": False,
            "enabled": True,
        },
        "dataset": {
            "dataset_name": DATASET_NAME,
            # `dataset_tag` is the SHORT identifier used for artifact /
            # run directory paths (`<ARTIFACTS_DIR>/<dataset_tag>/<variant>/
            # <timestamp>/`). It strips the technical suffixes that live
            # in `dataset_name` (`_coord_aligned`, `_shared_genes`) — those
            # belong to the silver / gold blob paths but make on-disk
            # artifact dirs unwieldy. If a future variant doesn't set
            # `dataset_tag`, the artifact path falls back to
            # `dataset_name`.
            "dataset_tag": "mmb0-1b_smb1-1b_1p",
            # adata_batch_idx are *positions* in the sorted DatasetBlob:
            #   idx 0 -> batch15 (STARmap+)   idx 1 -> batch82 (MERFISH)
            "adata_batch_idx": [0, 1],
            "root_data_dir": str(DATA_ROOT),
            # HVG subsetting — OFF for this dataset (431 curated genes).
            # Switch apply_hvg=True and set n_hvg to a smaller number when
            # running on larger multi-panel datasets where all genes are NOT
            # equally informative.
            "apply_hvg": False,
            "n_hvg": 2000,                    # only used when apply_hvg=True
            "gene_count_transform_names": [], # populated by train() based on apply_hvg
            "gene_count_transform_params": {"n_genes": 2000},
            "graph_params": {
                "spatial_key": "spatial",
                "delaunay": False,
                "n_neighs": 8,
                "radius": None,
                # Source for per-cell batch labels used by FiLM batch-correction
                # and by `build_batch_one_hot_from_obs`. When this column is
                # present in adata.obs at blob-build time, its values are
                # stored per-cell and used downstream (densified to contiguous
                # indices). When absent, the loader falls back to parsing
                # "batchN" substrings out of `obs['cell_id']`.
                "batch_key": "batch",
            },
            "feature_names": ["X"],
            "label_name": "cell_types",
            "train_transform_names": ["SpatialBatchSplit"],
            "train_transform_params": {
                "region": None,
                "train_batches": [15, 82],
                "val_batches": [],
                "test_batches": [],
                "xy_key": "xy_coordinates",
                # Cell-level holdout for in-distribution early stopping +
                # best-checkpoint-on-val. ONLY applied when `val_batches`
                # is empty (no whole-section holdout configured). When
                # `val_batches` is non-empty, that section IS the val set
                # — we do NOT additionally sub-sample training cells.
                # Adversarial training can be unstable late; a 10%
                # in-section val sample gives a stable in-distribution
                # signal that early stopping and best-ckpt-on-val use.
                # Set to 0.0 to disable.
                "train_val_cell_split": 0.10,
                "cell_split_seed":      0,
            },
        },
        "datamodule": {
            "loader_name": "NeighborLoader",
            "loader_params": {
                # batch_size pinned at 256. PAIRED with `max_epochs=80`
                # — together these are the canonical config that
                # produced the published-style niche NMI numbers
                # (~0.66-0.70 on the +enc-deeper+adv-warmup10 family).
                # See the long `max_epochs` history comment below for
                # the full rationale on why both knobs were reverted
                # in lockstep. Bigger batches require lr rescaling
                # (5e-4 * sqrt(new/256) for sqrt, 5e-4 * (new/256)
                # for linear) and post-hoc iLISI / niche-NMI
                # validation — don't change just one knob.
                "batch_size":         256,
                # 22 DataLoader workers. Kept high (the dataloader-
                # throughput knobs aren't part of the speedups
                # rolled back 2026-05-12 — the regression is on the
                # model / precision / optimizer side, not the data
                # side). Pair with `LSF_CORES=24` in the submit
                # scripts: 22 workers + 1 main proc + 1 spare = 24
                # cores. `_loader_perf_kwargs()` adds `pin_memory=True`,
                # `persistent_workers=True`, and `prefetch_factor=8`
                # automatically, so don't set those here (that
                # triggers `TypeError: got multiple values for
                # keyword argument` on the loader call).
                "num_workers":        22,
            },
            "sampler_name": "NeighborSampler",
            "sampler_params": {"num_neighbors": [8]},  # 1 hop = num_layers
            # Two-knob inference-sampling config:
            #
            #   `sample_neighbors_for_inference`: VAL + TEST loaders.
            #     `True`  (current): val/test use the training `[8]`
            #             fanout. Cheap per step → GPU stays fed
            #             between training epochs. Was the v11 fix
            #             for the spike-then-long-gap GPU pattern.
            #     `False` (legacy): val/test sample
            #             `num_neighbors=[-1]` (every neighbor).
            #             Heavier per step, slow val epochs, but
            #             deterministic and identical to predict.
            #
            #   `predict_sample_neighbors_for_inference`: PREDICT loader
            #             only — i.e. the final pass that writes
            #             `neighborhood_emb` / `cell_emb` to the
            #             output AnnData consumed by the benchmark
            #             figures.
            #     `False` (current, DEFAULT): fan out `[-1]` → every
            #             neighbor → deterministic per-cell niche
            #             embedding. Required for iLISI / MMD /
            #             NMI to be meaningful (with `[8]` the
            #             niche embedding picks up the
            #             sampling-noise-correlated-with-batch
            #             signature and iLISI collapses to 0).
            #     `True`: stochastic predict (e.g. dropout-style
            #             uncertainty). Don't enable for figure runs.
            #
            # Split rationale: val running every epoch wants the
            # cheap sampler for throughput, but the single final
            # predict pass should be the heavy deterministic one —
            # those are different cost-vs-correctness trade-offs.
            "inference_params": {
                "sample_neighbors_for_inference":         True,
                "predict_sample_neighbors_for_inference": False,
                # Predict-only batch-size override. Training batch is
                # 256 (tuned for adversarial gradient dynamics);
                # predict runs under torch.no_grad() so batch noise is
                # irrelevant and the cost is dominated by kernel-launch
                # overhead at small batch sizes.
                #
                # DEFAULT: 65536 (= 64×1024, bumped 8× from 8192 on
                # 2026-05-12). Predict-time math is unaffected by
                # batch grouping (codebook argmin is per-cell,
                # deterministic regardless of batch composition), so
                # bigger is purely a throughput win for the no-grad
                # forward pass.
                #
                # Memory math on the mmb-smb graph with `[-1]` predict
                # fanout (avg degree ~12):
                #   nodes_per_batch ≈ 65536 × 13 ≈ ~852k nodes/batch
                #   input X tensor   ≈ 852k × 431 genes × 4 B ≈ ~1.4 GiB
                #   + model activations (no autograd, no opt state):
                #     ~5-10 GiB on the s17_v2 spine, less on s25's
                #     128-dim tight spine.
                # Total peak GPU mem ~10-15 GiB on the wide spine,
                # ~5-8 GiB on the tight s25 spine — comfortable on
                # any H100/H200 (80+ GiB) and trivial on the
                # gpu_high_memory (384 GiB) class.
                #
                # Fallback chain on OOM (most likely on denser
                # datasets like chl59-8b_1p, or mmb20 with 20+
                # sections):
                #   65536 → 32768 → 16384 → 8192 → 4096 → 2048 → 1024.
                "predict_batch_size":                     65536,
                # Val/test batch-size override. Val runs every
                # `check_val_every_n_epoch` (see trainer config below
                # — currently every 2 train epochs), and the per-val-
                # pass overhead used to be visible as a periodic
                # ~0% GPU-utilisation dip in wandb. Bumping val to
                # 4096 (= 16× training) makes each val pass ~4-8×
                # faster, shrinking those dips to near-invisible.
                # Val fanout is lighter than predict's [-1] (val uses
                # `sample_neighbors_for_inference=True` -> [8]), so
                # val can comfortably go larger than predict without
                # OOM. Same fallback logic as predict_batch_size if
                # you ever see val-time OOM:
                # 4096 → 2048 → 1024 → 512.
                "val_batch_size":                         4096,
                # Pre-cache one full epoch of training batches on the
                # first `train_dataloader()` call, then serve them from
                # CPU memory on every subsequent epoch (reshuffled order,
                # fixed content).
                #
                # DEFAULT: False  (BACKED OFF 2026-05-12).
                #
                # The cache path was on briefly with an internal
                # `num_neighbors=[-1]` override (every cell sees its
                # full neighborhood, frozen for all 80 epochs). Multi-
                # seed runs on that config dropped niche / cell metrics
                # severely vs the s17_v2 historic numbers — most
                # plausibly because:
                #   (a) The niche-branch GNN was trained with
                #       stochastic `[8]`-fanout sampling, so the
                #       per-epoch resampling acted as data
                #       augmentation. Freezing the neighbourhood
                #       (let alone freezing the FULL neighbourhood)
                #       removed that and pushed nbr_NMI / nbr_iLISI
                #       down.
                #   (b) The cached batches are ~2× bigger in node
                #       count than the live-sampled batches, which
                #       changes the per-step gradient and possibly
                #       OOM behaviour on smaller GPUs.
                # Neither (a) nor (b) was caught by a smoke test —
                # only the full multi-seed sweep surfaced the
                # regression. Default reverted to False until we have
                # a clean A/B vs the historic baseline.
                #
                # The plumbing (the kwarg in `InMemoryDataModule`, the
                # internal `[-1]` override, the `.cpu()` defensive
                # copy) is kept in place; opt back in by setting
                # `cache_train_batches: True` here or in a per-variant
                # patch once we trust it again. For sampler-heavy
                # datasets (chl59, mmb20) it's also worth keeping the
                # option visible.
                #
                # Lives in `inference_params` only because that's the
                # dict the initialiser unpacks into `InMemoryDataModule`'s
                # kwargs. It's a TRAIN-side flag (val/test/predict are
                # unaffected) — don't read meaning into the name.
                # CONFIRMED CULPRIT 2026-05-12: `cache_train_batches=True`
                # caused the multi-seed regression. The single-flip A/B
                # showed metrics dropping severely when only this knob
                # was changed (everything else was historic-compatible).
                # The cache-build internal [-1] fanout override (see
                # `in_memory_datamodule.py` `train_dataloader`) is the
                # most likely mechanism: freezing the full per-cell
                # neighborhood removes the per-epoch [8]-sample
                # regularisation the niche GNN depends on. Keeping the
                # default OFF; the plumbing stays available behind the
                # flag for future investigation.
                "cache_train_batches":                    False,
            },
        },
        "model": {
            "model_name": "VQNiche",
            "encoder_name": "VQNiche_Encoder",
            "attribute_decoder_name": "MLPSoftmax",
            "adjacency_decoder_name": "MLP_AdjacencyDecoder",
            "predictor_name": "Linear",
            "imputation_params": {
                "mask_strategy": "original",
                "base_mask_ratio": 0.0,
                "final_mask_ratio": 0.0,
                "warmup_epochs": 0,
                "deterministic_masking": False,
                "compute_mask_input_diversity": False,
                "mask_token_eps": 0.0001,
            },
            # All Pearson metrics are reported on every variant.
            # Neighbourhood metrics (1hop_nbr) are silently skipped when
            # X_nbr / X_hat_nbr are absent (recon_mode='cell' variants).
            # In-training metric computation is OFF by default. Both
            # lists are populated by `_resolve_metrics_list()`, which
            # returns `[]` unless `SQUINT_WITH_PEARSON=1` is set
            # (passing `--with-pearson` to `main()` exports that env
            # var automatically). See the module-level docstring for
            # `_resolve_metrics_list()` for the full rationale.
            #
            # Why both lists use the same source:
            #   - train_metrics_list is consumed by
            #     BaseModel.compute_metrics(mode='train' | 'val'),
            #     fired from on_validation_epoch_end.
            #   - test_metrics_list is consumed by the same helper
            #     with mode='test', fired from trainer.test().
            # The standard pipeline doesn't call trainer.test() (we
            # use predict + compute_inference_metrics.py instead), so
            # test_metrics_list is essentially dormant. But aligning
            # it with train avoids surprise behaviour if anyone wires
            # in a test loop later, and keeps a single switch for
            # "Pearson on / off everywhere during PL hooks".
            "train_metrics_list": _resolve_metrics_list(),
            "test_metrics_list":  _resolve_metrics_list(),
            "encoder_params": {
                "gnn_name": "SAGEConv",
                "mlp_params": {
                    "hidden_channels": [400, 256],
                    "dropout": 0.0,
                    "act": "relu",
                    "norm": None,
                },
                "gnn_params": {
                    # Latent dim doubled from 128 -> 256: this is the codebook
                    # embedding dim for ALL VQ variants. With codebook=30 and
                    # 431 input genes, 128 was a tight bottleneck; 256 gives
                    # the codebook ~2x more representational capacity.
                    "hidden_channels": 256,
                    "num_layers": 1,
                    "act_first": True,
                    "activation": "relu",
                    "norm": None,
                    "dropout": 0.0,
                    "init_method": "kaiming_uniform",
                },
                # POC: no FiLM conditioning
                "vq_params": {
                    "vq_name": "VectorQuantize",
                    "freeze_codebook": False,
                    "use_cosine_sim": True,
                    "ema_update": True,
                    "manual_ema_update": False,
                    "threshold_ema_dead_code": 2,
                    "manual_in_place_optimizer_update": False,
                    "learnable_codebook": False,
                    "codebook_size": 30,
                    "heads": 1,
                    "separate_codebook_per_head": False,
                    "decay": 0.8,
                    "eps": 0.00001,
                    "kmeans_init": True,
                    "kmeans_iters": 10,
                    "sync_kmeans": True,
                    "sample_codebook_temp": 0.0,
                    "commitment_weight": 0.0,
                    "commitment_use_cross_entropy_loss": False,
                    "codebook_diversity_loss_weight": 0.0,
                    "codebook_diversity_temperature": 100.0,
                    "orthogonal_reg_weight": 0.0,
                    "orthogonal_reg_max_codes": None,
                    "orthogonal_reg_active_codes_only": False,
                },
            },
            "attribute_decoder_params": {
                "apply_conditioning": None,
                "mlp_params": {
                    # Decoder depth bumped from [400] -> [400, 400] to give
                    # the NB-mean head more capacity to expand the 256-dim
                    # latent into a 431-gene rate vector.
                    "hidden_channels": [400, 400],
                    "dropout": 0.0,
                    "act": "gelu",
                    "norm": "layer_norm",
                },
            },
            "adjacency_decoder_params": {
                "out_channels": 128,
                "mlp_params": {
                    "hidden_channels": [64],
                    "dropout": 0.0,
                    "act": "relu",
                    "norm": "layer_norm",
                },
            },
            "optimizer_params": {
                "optimizer_name": "adam",
                "lr": 0.0005,
                "weight_decay": 0.001,
                "mask_lr_scale": 1.0,
                # `fused=True` coalesces parameter updates into a single
                # CUDA kernel instead of per-tensor launches. 5-15%
                # wall-clock saving on the optimizer step for SQUINT's
                # many-small-tensor regime.
                #
                # DEFAULT: False (REVERTED 2026-05-12, third pass).
                #
                # Turned off as the new bisection suspect after the
                # conservative-baseline rollback didn't restore
                # metrics. In theory fused Adam is mathematically
                # identical to the unfused path (same Adam update,
                # just better-batched kernels), but: torch's fused
                # Adam has had bf16-master-weight + dynamic-graph
                # edge cases in the past, and some PyTorch versions
                # silently skip the codebook EMA params (which have
                # `requires_grad=False` but still need to flow
                # through `optimizer.step` for the rest of the model
                # to update correctly). If toggling this off
                # restores metrics, we'll know fused is the culprit
                # and look at it post-deadline.
                "fused": False,
            },
            "loss_params": {
                "loss_names": [
                    "nb_attribute_reconstruction_loss",
                    "mse_commit_loss",
                ],
                "loss_kwargs": {
                    # recon_mode controls which NB targets are computed:
                    #   "cell" -> per-cell (default baseline)
                    #   "nbr"  -> 1-hop neighbourhood mean (niche-aware signal)
                    #   "both" -> cell + neighbourhood (requires adding
                    #             nb_attribute_reconstruction_loss_nbr to loss_names)
                    "recon_mode": "cell",
                    "only_masked": False,
                    "edge_sampling_ratio": 2,
                    "use_pos_weight": True,
                    "estimate_adj_kwargs": {"nonlinearity": "sigmoid", "k": 8},
                    "wt_attr_reconstr": 1.0,
                    "wt_attr_reconstr_nbr": 1.0,
                    # Code-conditional dispersion. When enabled, a small MLP
                    # maps z_q -> log(theta) per-cell-per-gene, replacing the
                    # global per-gene scalar parameter. Default OFF; ablate
                    # via a future +ccd patch.
                    # Format options:
                    #   False                              -> off
                    #   True                               -> on, linear head (no hidden)
                    #   {"enabled": True, "hidden_channels": [128]}
                    "code_conditional_dispersion": False,
                    # Adjacency-loss input mode.
                    # False (default): edge logits = h_adj_i^T h_adj_j where
                    #     h_adj is the output of the MLP adjacency_decoder.
                    # True            : edge logits = z_q_i^T z_q_j (the
                    #     quantized latent itself).  This is the
                    #     NicheCompass / standard graph-VAE formulation —
                    #     forces the codebook embeddings to directly encode
                    #     pairwise spatial proximity, which is exactly the
                    #     bias we want when codes should capture niches.
                    "bypass_adj_decoder": False,
                    "wt_commit": 1.0,
                },
            },
        },
        "trainer": {
            # Best-checkpoint metric: val_loss (sum of all weighted loss
            # terms over the in-distribution VAL set — same 10% cell-level
            # holdout from the training sections that early stopping
            # watches; see `train_val_cell_split`). Single source of truth
            # for "best epoch" — the saved ckpt is the one early stopping
            # would have stopped at. Robust to adversarial late-stage
            # instability: when the encoder oscillates, val_loss climbs
            # before train_loss does, so the kept snapshot is from before
            # the drift.
            "monitor": "val_loss",
            "checkpoint_params": {"mode": "min", "save_top_k": 1, "save_last": True},
            # max_epochs is the universal training budget cap — every
            # individual / multi-seed / ablation run picks this value
            # up from the base config. At batch=256 / ~100k-cell
            # dataset that's ~390 gradient steps/epoch, so 80 epochs
            # ≈ 31k total gradient steps.
            #
            # HISTORY (don't repeat the cycle):
            #
            #   - Original (2026-04 / early 2026-05): max_epochs=80,
            #     batch=256, lr=5e-4. The "good" Pareto: niche NMI
            #     ~0.66-0.70 on the +enc-deeper+adv-warmup10 family.
            #
            #   - 2026-05-11 v11 push: bumped to (1024, 200) to chase
            #     GPU duty cycle. lr was NOT rescaled; per-sample
            #     gradient dropped 4x; adversarial discriminator
            #     under-trained; `neighborhood_emb` iLISI collapsed to
            #     numerical noise. Reverted.
            #
            #   - 2026-05-12 partial revert: (256, 200) — i.e. kept the
            #     extended budget but restored the small-batch
            #     dynamics. Result: niche NMI dropped ~0.03-0.05 across
            #     EVERY variant in the v12-v16 ablations (0.69 -> 0.62
            #     family). Cause: early-stopping monitor is `val_loss`,
            #     which keeps inching down on the adversarial CE +
            #     reconstruction terms even when the encoder is
            #     over-correcting batch effects. With patience=20 +
            #     min_delta=0.1, stopping never fires before epoch 200,
            #     and the saved "best val_loss" checkpoint lands in
            #     the over-corrected regime — niche structure
            #     forgotten.
            #
            #   - Now (2026-05-12): reverted to max_epochs=80, the
            #     working budget. Don't bump this in isolation again.
            #     If you ever want to revisit "long-train better
            #     Pareto", do it with a niche-quality-aware checkpoint
            #     monitor (e.g. `val_pearson_gene_wise_1hop_nbr_log1p`
            #     via SQUINT_WITH_PEARSON=1) AND verify post-hoc
            #     niche NMI before publishing.
            "max_epochs": 80,
            # Training precision.
            #
            # DEFAULT: "32-true" (full rollback to pre-session
            # baseline 2026-05-12). All efficiency knobs are off
            # EXCEPT `deterministic=False / benchmark=True` (kept
            # below). Opt back in per-run with `--precision bf16-mixed`
            # once the conservative config confirms metrics back at
            # historic.
            "precision": "32-true",
            # Determinism vs benchmark mode.
            #
            # `deterministic: True` (DEFAULT, REVERTED 2026-05-12).
            # Was briefly False (with `benchmark=True`) for a 5-10%
            # wall-clock saving via cuDNN autotune; reverted after
            # the autotune-driven kernel variation turned out to
            # destabilise adversarial training on multiple variants
            # (CE jumped + early stopping fired). Adversarial min-max
            # is genuinely sensitive to per-step numerical
            # differences — cuDNN benchmark mode picks different
            # kernels per shape across runs, and the accumulated
            # noise breaks the encoder/discriminator co-evolution.
            #
            # Implies `benchmark=False` in the Trainer (Lightning
            # forces this when deterministic=True). Override per-run
            # via the `--deterministic`/`--no-deterministic` flags
            # if you want to A/B test benchmark mode on a non-
            # adversarial variant.
            "deterministic": True,
            # Lightning Trainer strategy.
            #
            # DEFAULT: "ddp_find_unused_parameters_true" (historic value,
            # REVERTED 2026-05-12). Was briefly "auto" — empirically
            # that turned out to destabilise adversarial training
            # across multiple variants (CE jumped + early stopping
            # fired). My earlier claim that "strategy=auto only
            # changes the Lightning wrapper class, not the math"
            # turned out to be wrong for SQUINT's adversarial dynamics
            # — Lightning's `find_unused_parameters_true` path
            # interacts with the GRL branch's gradient handling in a
            # way that single-device strategy doesn't, and the
            # difference is enough to flip the adversarial min-max
            # game on this workload. Sticking with the historic
            # default. Override per-run via `--strategy <STR>` for
            # experimentation only.
            "strategy": "ddp_find_unused_parameters_true",
            # torch.compile the model after init.
            #
            # DEFAULT: False (REVERTED 2026-05-12 after empirical test).
            #
            # The compile path is fully implemented and crash-free
            # (the VQ `gumbel_sample` incompatibility is handled by
            # `_install_compile_safe_one_hot()` — see definition near
            # `train()`). HOWEVER, on a multi-seed test run, compile
            # made wall-clock SLOWER, not faster. Most likely cause:
            # the compile / autotune cost per first-time shape isn't
            # amortised across enough iterations because:
            #   - The dataset has only ~340 batches/epoch at bs=256;
            #     `dynamic=True` still recompiles a few times for
            #     extreme-end shapes during the first epoch.
            #   - SQUINT's per-step compute is so small that even a
            #     few extra ms of dynamo overhead per step wipes out
            #     the kernel-fusion savings.
            # Opt back in via `--compile` once we have a way to keep
            # compile cheap (e.g. AOT compile + cached recompiles
            # across seeds), or for runs with a much higher per-step
            # cost (bigger batch, deeper model).
            "compile_model": False,
            # Run validation every 2 train epochs (Lightning default
            # would be every epoch). Each val pass is a sub-pass over
            # `val_dataloader` (cell-level 10% holdout from the train
            # split) which causes GPU utilization to dip to ~0% while
            # the train DataLoader workers idle and the val workers
            # spin up. On a ~50s/epoch budget those dips cost ~20% of
            # total throughput. Halving the val frequency recovers
            # ~10% wall-clock with no model risk — early stopping
            # (patience=20 val passes = 40 train epochs at this
            # setting) and best-checkpoint selection still work
            # exactly as before, just on a coarser val grid.
            "check_val_every_n_epoch": 2,
            "enable_checkpointing": True,
            "ckpt_path": "best",
            # Early stopping: watch the val_loss (= sum of all weighted
            # loss terms over the val set). Switching from train_loss to
            # val_loss makes early stopping respond to in-distribution
            # generalisation rather than the optimisation objective on
            # the training set, which matters in particular for the
            # adversarial variants where train_loss can keep declining
            # while val performance silently degrades.
            #
            # patience=10 VAL PASSES — IMPORTANT: Lightning counts
            # `patience` in val passes, not train epochs. With
            # `check_val_every_n_epoch=2` (see trainer config above),
            # one val pass = two train epochs, so patience=10 here
            # means "stop if val_loss hasn't improved for 20 train
            # epochs" — same effective horizon as the original
            # patience=20 / val-every-epoch setup.
            #
            # 20 train epochs ≈ 8k gradient steps at
            # batch_size=256 / ~100k cells — enough to distinguish
            # a true plateau from a codebook reshuffle, and enough
            # to ride through the adversarial alpha ramp-up that
            # comes after `adv-warmup10` (otherwise patience can
            # fire during the 10-epoch warm-up + ~5 post-warm-up
            # epochs, before the adv-driven val_loss drift has had
            # time to stabilise).
            #
            # min_delta=0.1: small absolute, but val_loss in this
            # codebase ranges ~140-170 so 0.1 ≈ 0.07% relative.
            "early_stopping_params": {
                "enabled":    True,
                "monitor":    "val_loss",
                "mode":       "min",
                "patience":   10,    # 10 val passes × 2 train epochs/pass = 20 train epochs
                "min_delta":  0.1,
            },
        },
    }


# ---------------------------------------------------------------------------
# 2b. Training config — full SQUINT (FiLM + masking + adjacency)
# ---------------------------------------------------------------------------

# ---------------------------------------------------------------------------
# 2b. Ablation patch helpers
# ---------------------------------------------------------------------------
# Each patch is a small function that mutates a DEEP COPY of a base config and
# returns it. A patch changes ONE design component so its effect can be
# isolated. Compose patches to build compound variants.
#
# The full materialised config is always saved to disk per run, so
# reproducibility does not depend on patch helpers being preserved.
# ---------------------------------------------------------------------------

def _copy(cfg: dict) -> dict:
    import copy
    return copy.deepcopy(cfg)


# ---- Reconstruction mode ---------------------------------------------------

def _patch_recon_cell(cfg: dict) -> dict:
    """Per-cell NB reconstruction only (baseline). Explicitly sets recon_mode."""
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["recon_mode"] = "cell"
    losses = cfg["model"]["loss_params"]["loss_names"]
    # Ensure only the cell loss is present, remove nbr branch if any.
    if "nb_attribute_reconstruction_loss_nbr" in losses:
        losses.remove("nb_attribute_reconstruction_loss_nbr")
    if "nb_attribute_reconstruction_loss" not in losses:
        losses.insert(0, "nb_attribute_reconstruction_loss")
    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


def _patch_recon_nbr(cfg: dict) -> dict:
    """
    Neighbourhood-only NB reconstruction.
    Per-cell NB is deactivated: recon_mode='nbr' makes training_step route
    the 1-hop-aggregated pair through the legacy pred_attr/target_attr keys
    so `nb_attribute_reconstruction_loss` computes NB on neighbourhood means.
    Per-cell counts are not reconstructed in this variant.
    """
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["recon_mode"] = "nbr"
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "nb_attribute_reconstruction_loss_nbr" in losses:
        losses.remove("nb_attribute_reconstruction_loss_nbr")
    if "nb_attribute_reconstruction_loss" not in losses:
        losses.insert(0, "nb_attribute_reconstruction_loss")
    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


def _patch_recon_both(cfg: dict) -> dict:
    """
    Per-cell + 1-hop neighbourhood NB reconstruction simultaneously.
    Uses TWO separate loss dispatches:
      nb_attribute_reconstruction_loss     -> cell pair (pred_attr / target_attr)
      nb_attribute_reconstruction_loss_nbr -> nbr pair  (pred_attr_nbr / target_attr_nbr)
    Weighted equally by default (wt_attr_reconstr = wt_attr_reconstr_nbr = 1.0).
    """
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["recon_mode"] = "both"
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "nb_attribute_reconstruction_loss" not in losses:
        losses.insert(0, "nb_attribute_reconstruction_loss")
    if "nb_attribute_reconstruction_loss_nbr" not in losses:
        idx = losses.index("nb_attribute_reconstruction_loss") + 1
        losses.insert(idx, "nb_attribute_reconstruction_loss_nbr")
    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


# ---- Adjacency reconstruction ----------------------------------------------

def _patch_adj(cfg: dict, weight: float = 1.0) -> dict:
    """
    Add BCE adjacency reconstruction loss.
    The adjacency decoder predicts which pairs of cells in the seed-node
    induced subgraph are connected in the 8-NN spatial graph. Pushes the
    H_adj latent toward encoding local spatial topology.
    Does NOT change recon_mode — stack with a recon patch for combinations.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "bce_adjacency_reconstruction_loss" not in losses:
        losses.append("bce_adjacency_reconstruction_loss")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_adj_reconstr"] = float(weight)
    return cfg


# ---- FiLM conditioning -----------------------------------------------------

def _patch_film(cfg: dict) -> dict:
    """
    Add FiLM (feature-wise linear modulation) conditioning on
    (rbf_distances, cell_batch_id) in both encoder and attribute decoder.
    Enables the model to distinguish cells from different batches / spatial
    scales without leaking batch identity into the VQ codebook.
    """
    film_params = {
        "condition_list": ["rbf_distances", "cell_batch_id"],
        "use_bias": True,
        "use_residual": False,
        "residual_weight": 0.2,
        "init_mode": "identity",
    }
    cfg["model"]["encoder_params"]["conditioning_params"] = film_params.copy()
    cfg["model"]["attribute_decoder_params"]["apply_conditioning"] = "in-MLP"
    cfg["model"]["attribute_decoder_params"]["conditioning_params"] = film_params.copy()
    cfg["model"]["optimizer_params"]["mask_lr_scale"] = 1.0  # unchanged here
    return cfg


# ---- MAE-style masking -----------------------------------------------------

def _patch_masking(cfg: dict,
                   base_ratio: float = 0.2,
                   final_ratio: float = 0.6,
                   warmup: int = 5) -> dict:
    """
    Enable MAE-style gene masking. A learnable mask token replaces a random
    fraction of input genes; the model must reconstruct all genes from the
    partial signal. Forces the encoder to propagate neighbourhood context
    rather than copying the input. mask_lr_scale=2.0 gives the mask token
    a higher LR so it moves fast relative to the rest of the network.
    """
    cfg["model"]["imputation_params"] = {
        "mask_strategy": "learnable_parameter",
        "base_mask_ratio": base_ratio,
        "final_mask_ratio": final_ratio,
        "warmup_epochs": warmup,
        "deterministic_masking": False,
        "compute_mask_input_diversity": False,
        "mask_token_eps": 0.0001,
    }
    cfg["model"]["optimizer_params"]["mask_lr_scale"] = 2.0
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "mask_token_regularization" not in losses:
        losses.append("mask_token_regularization")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_mask_token_regularization"] = 0.001
    return cfg


# ---- Multi-head VQ ---------------------------------------------------------

def _patch_multihead_vq(cfg: dict, heads: int = 10, codebook_size: int = 5000) -> dict:
    """
    Switch from a single 30-code codebook to a multi-head VQ with `heads`
    parallel codebooks of size `codebook_size` each. Total number of
    representable niche combinations = codebook_size^heads (exponential), but
    the model learns to use a much smaller effective set. Used in full SQUINT.
    """
    cfg["model"]["encoder_params"]["vq_params"].update({
        "codebook_size": codebook_size,
        "heads": heads,
        "separate_codebook_per_head": False,
    })
    return cfg


# ---- Residual VQ (RQ-VAE) --------------------------------------------------

def _patch_rvq(cfg: dict, codebook_sizes=(30, 200)) -> dict:
    """
    Switch the VQ to ResidualVQ_Squint: an L-level residual quantizer where
    each cell is encoded as a SUM of L codes drawn from L independent
    codebooks of (potentially different) sizes.

    Default: levels=[30, 200] -> 30 * 200 = 6000 distinct quantized
    representations, with a clean coarse->fine interpretation.
    Level 1 (30) acts as the macro niche; level 2 (200) as a refinement
    code applied uniformly across the whole space (no per-bucket codebook).

    The lucidrains-internal commit_loss is left at 0 (commitment_weight=0.0)
    so that the external `mse_commit_loss` remains the single source of
    commit signal — same convention as the rest of the variants.
    """
    sizes = list(codebook_sizes)
    cfg["model"]["encoder_params"]["vq_params"] = {
        "vq_name": "ResidualVQ_Squint",
        "num_quantizers": len(sizes),
        "codebook_size": sizes,             # accepted as list by our wrapper
        "use_cosine_sim": True,
        "ema_update": True,
        "decay": 0.8,
        "eps": 0.00001,
        "threshold_ema_dead_code": 2,       # only applied to level 1 internally
        "kmeans_init": True,                # only applied to level 1 internally
        "kmeans_iters": 10,
        "sync_kmeans": True,
        "commitment_weight": 0.0,
        "sample_codebook_temp": 0.0,
    }
    return cfg


# ---- Conditional / Tree VQ -------------------------------------------------

def _patch_cvq(cfg: dict, k1: int = 30, k2: int = 10) -> dict:
    """
    Switch the VQ to ConditionalVQ: a true 2-level tree where each level-1
    code (K1 of them) selects a separate level-2 codebook (K1 codebooks of
    K2 codes each).

    Default: K1=30, K2=10 -> 300 distinct quantized representations,
    organised hierarchically. With ~100k cells / 30 buckets ≈ 3300 cells per
    bucket / 10 codes ≈ 330 cells per (l1, l2) pair, level-2 codebooks have
    enough data to train cleanly.

    Level-2 codebooks have kmeans_init disabled and dead-code resampling
    disabled (per-bucket data is too sparse to cluster reliably and we don't
    want to spuriously revive level-2 codes in small buckets).
    """
    cfg["model"]["encoder_params"]["vq_params"] = {
        "vq_name": "ConditionalVQ",
        "codebook_size_l1": int(k1),
        "codebook_size_l2": int(k2),
        "use_cosine_sim": True,
        "ema_update": True,
        "decay": 0.8,
        "eps": 0.00001,
        "threshold_ema_dead_code": 2,
        "kmeans_init": True,
        "kmeans_iters": 10,
        "sync_kmeans": True,
        "commitment_weight": 0.0,
        "sample_codebook_temp": 0.0,
    }
    return cfg


# ---- NicheCompass-style adjacency reconstruction ---------------------------

def _patch_nichecompass_adj(cfg: dict, weight: float = 1.0) -> dict:
    """
    Switch the BCE adjacency reconstruction to the NicheCompass / standard
    graph-VAE formulation, and weight it on par with the gene-expression NB
    loss (default `weight=1.0`).

    Two changes vs. `_patch_adj`:
      (a) `bypass_adj_decoder=True` makes the BCE compute its edge logits
          directly on the quantized latent z_q (raw inner product
          z_q_i^T z_q_j), bypassing the SQUINT adjacency_decoder MLP. This
          mirrors NicheCompass's `A_hat = sigmoid(Z @ Z^T)` formulation —
          there is no extra non-linearity between the latent and the
          edge prediction. The codebook embeddings themselves are forced
          to encode pairwise spatial proximity.
      (b) `wt_adj_reconstr=1.0` (vs. the legacy default 0.1) gives the
          edge reconstruction roughly the same loss-magnitude footprint as
          NB attribute reconstruction. The NicheCompass user guide
          explicitly notes that "finding a balance between gene expression
          and edge reconstruction is a key element for good niche
          identification" — the default 0.1 weight in SQUINT was 10x too
          weak for a niche-focused signal.

    Adds `bce_adjacency_reconstruction_loss` to the loss list if not
    already present.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "bce_adjacency_reconstruction_loss" not in losses:
        losses.append("bce_adjacency_reconstruction_loss")
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["wt_adj_reconstr"]    = float(weight)
    lk["bypass_adj_decoder"] = True
    return cfg


# ---- GATv2 encoder (NicheCompass-style GNN) --------------------------------

def _patch_gatv2_encoder(cfg: dict) -> dict:
    """
    Switch the encoder GNN from GraphSAGE to GATv2 (dynamic attention).
    NicheCompass recommends GATv2 over GCN/GraphSAGE for niche-focused
    representations — attention weights are spatially adaptive, so cells
    in dense parts of a niche aggregate from more informative neighbours
    than cells at niche boundaries.

    The MLP / hidden-channel / depth structure is left unchanged — this
    patch only flips `gnn_name`. Use it stacked with a recon patch and
    `_patch_nichecompass_adj` to get a NicheCompass-shaped pipeline.
    """
    cfg["model"]["encoder_params"]["gnn_name"] = "GATv2Conv"
    return cfg


# ---------------------------------------------------------------------------
# 2c. Variant registry
# ---------------------------------------------------------------------------
# Naming convention: <recon-mode>[+<component>][+<component>...]
#   recon-cell   per-cell NB only
#   recon-nbr    neighbourhood NB only
#   recon-both   per-cell + neighbourhood NB
#   +adj         + adjacency reconstruction
#   +film        + FiLM conditioning
#   +mask        + MAE-style masking
#   +mhvq        + multi-head VQ
#   full         every component active
# ---------------------------------------------------------------------------

def _B():
    """Shorthand: deep-copy of the base POC config."""
    return _copy(make_train_config_poc())


# ---------------------------------------------------------------------------
# 2c. VQNiche_Dual: dual-codebook config builder
# ---------------------------------------------------------------------------
# The dual model (`VQNiche_Dual`) has a separate cell and niche codebook + a
# separate decoder for each branch. The config below is built by starting
# from the single-codebook POC config and then:
#   - replacing model_name/encoder_name with the dual classes
#   - replacing `vq_params` with `vq_cell_params` + `vq_niche_params`
#   - replacing `attribute_decoder_params` with `attribute_decoder_cell_params`
#     + `attribute_decoder_niche_params`
#   - replacing `loss_names` with the dual loss list
#   - dropping `adjacency_decoder_params` (the dual model uses a direct
#     cosine-similarity adjacency BCE on z_q_niche, so there is no MLP
#     adjacency decoder)
# ---------------------------------------------------------------------------

def _default_vq_params(codebook_size: int = 30) -> dict:
    """
    Single-codebook (non-hierarchical) VectorQuantize defaults, identical
    settings as the POC config so cell- and niche-branches start from a
    matched VQ baseline. Swap in `_default_rvq_params(...)` for hierarchical.
    """
    return {
        "vq_name": "VectorQuantize",
        "freeze_codebook": False,
        "use_cosine_sim": True,
        "ema_update": True,
        "manual_ema_update": False,
        "threshold_ema_dead_code": 2,
        "manual_in_place_optimizer_update": False,
        "learnable_codebook": False,
        "codebook_size": int(codebook_size),
        "heads": 1,
        "separate_codebook_per_head": False,
        "decay": 0.8,
        "eps": 0.00001,
        "kmeans_init": True,
        "kmeans_iters": 10,
        "sync_kmeans": True,
        "sample_codebook_temp": 0.0,
        "commitment_weight": 0.0,
        "commitment_use_cross_entropy_loss": False,
        "codebook_diversity_loss_weight": 0.0,
        "codebook_diversity_temperature": 100.0,
        "orthogonal_reg_weight": 0.0,
        "orthogonal_reg_max_codes": None,
        "orthogonal_reg_active_codes_only": False,
    }


def _default_rvq_params(codebook_sizes=(30, 200)) -> dict:
    """Residual-VQ defaults (hierarchical). Plug into vq_cell_params or vq_niche_params."""
    return {
        "vq_name": "ResidualVQ_Squint",
        "num_quantizers": len(codebook_sizes),
        "codebook_size": list(codebook_sizes),
        "use_cosine_sim": True,
        "ema_update": True,
        "decay": 0.8,
        "eps": 0.00001,
        "threshold_ema_dead_code": 2,
        "kmeans_init": True,
        "kmeans_iters": 10,
        "sync_kmeans": True,
        "commitment_weight": 0.0,
        "sample_codebook_temp": 0.0,
        # Codebook-diversity loss (lucidrains feature) — propagated to
        # EVERY inner VectorQuantize level. 0.0 = legacy off. >0 adds a
        # softmax-similarity repulsion that pushes codes apart on the
        # embedding sphere (SwAV-style prototype repulsion). Use the
        # `_patch_dual_codebook_diversity` patch to enable.
        "codebook_diversity_loss_weight": 0.0,
        "codebook_diversity_temperature": 100.0,
    }


def _default_cvq_params(
        k1: int = 30,
        k2: int = 10,
        k3: Optional[int] = None,
    ) -> dict:
    """Conditional / tree VQ defaults. Plug into vq_cell_params or vq_niche_params.

    `k3=None` (default) gives the legacy 2-level CVQ (K1 macro buckets,
    K2 sub-children each — K1 × K2 distinct codes). Passing an integer
    `k3` activates 3-level CVQ: K1 × K2 × K3 distinct codes, with one
    leaf VQ of size K3 per (l1, l2) bucket. The 3-level pass is wired
    inside `ConditionalVQ.forward` and exposes `num_quantizers=3` so
    downstream codebook-utilisation metrics stratify all three levels.
    """
    out = {
        "vq_name": "ConditionalVQ",
        "codebook_size_l1": int(k1),
        "codebook_size_l2": int(k2),
        "use_cosine_sim": True,
        "ema_update": True,
        "decay": 0.8,
        "eps": 0.00001,
        "threshold_ema_dead_code": 2,
        "kmeans_init": True,
        "kmeans_iters": 10,
        "sync_kmeans": True,
        "commitment_weight": 0.0,
        "sample_codebook_temp": 0.0,
    }
    if k3 is not None:
        # ConditionalVQ.__init__ accepts `codebook_size_l3` as an
        # optional kwarg (None -> legacy 2-level). Setting it here
        # activates the 3-level pass.
        out["codebook_size_l3"] = int(k3)
    return out


def make_train_config_dualvq() -> dict:
    """
    Build the base config for VQNiche_Dual.

    Defaults (per design D1–D6):
      - encoder: shared MLP [400, 256], GraphSAGE GNN with hidden=256,
        num_layers=1 (matches POC config)
      - vq_cell  = VectorQuantize(k=30) on the post-MLP latent
      - vq_niche = VectorQuantize(k=30) on the post-GNN latent
      - cell decoder + niche decoder are independent MLPSoftmax with
        hidden_channels=[400, 400] each
      - losses (all weights = 1.0):
          nb_attribute_reconstruction_loss          (cell branch NB)
          nb_attribute_reconstruction_loss_nbr      (niche branch NB,
                                                     aggregated post-decoder)
          mse_commit_loss_cell
          mse_commit_loss_niche
          bce_cosine_adjacency_reconstruction_loss  (on z_q_niche, cosine sim,
                                                     NicheCompass-style)
      - adjacency BCE uses cosine_temperature=0.1, weight=250 (heavily
        upweighted to balance against gene-NB ~150 nats — empirical sweet
        spot on the MERFISH/STARmap MB panel)
      - cosine-similarity adjacency operates on z_gnn (continuous niche
        embedding, NicheCompass-faithful) by default; switch via
        `loss_kwargs['adj_loss_input'] = 'z_q_niche'` to use the
        quantized version
      - the BCE input tensor is the FULL batch (including sampled
        neighbours) so negative-edge sampling has enough nodes
    """
    cfg = make_train_config_poc()

    # --- model class names ------------------------------------------------
    cfg["model"]["model_name"]   = "VQNiche_Dual"
    cfg["model"]["encoder_name"] = "VQNiche_Dual_Encoder"
    cfg["model"]["adjacency_decoder_name"] = None   # not used

    # --- encoder: replace single vq_params with two slots ----------------
    enc = cfg["model"]["encoder_params"]
    enc["vq_cell_params"]  = _default_vq_params(codebook_size=30)
    enc["vq_niche_params"] = _default_vq_params(codebook_size=30)
    enc.pop("vq_params", None)   # legacy single-codebook key — removed

    # --- two attribute decoders ------------------------------------------
    cfg["model"]["attribute_decoder_cell_params"]  = _copy(cfg["model"]["attribute_decoder_params"])
    cfg["model"]["attribute_decoder_niche_params"] = _copy(cfg["model"]["attribute_decoder_params"])
    cfg["model"].pop("attribute_decoder_params", None)
    cfg["model"].pop("adjacency_decoder_params",  None)

    # --- losses & weights -------------------------------------------------
    # Niche NB uses the *_dual variant so it reads `dispersion_niche` instead
    # of `dispersion` — i.e. the niche branch has its own per-gene NB
    # dispersion, decoupled from the cell branch's dispersion. This is
    # essential because the per-cell counts (cell branch) and the
    # neighbourhood-mean counts (niche branch) have very different variance
    # structure; sharing the dispersion forces a compromise that makes the
    # cell-branch NB loss drift up over training.
    cfg["model"]["loss_params"]["loss_names"] = [
        "nb_attribute_reconstruction_loss",            # cell branch
        "nb_attribute_reconstruction_loss_nbr_dual",   # niche branch (separate theta)
        "mse_commit_loss_cell",
        "mse_commit_loss_niche",
        "bce_cosine_adjacency_reconstruction_loss",    # on z_q_niche
    ]
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    # Drop legacy single-codebook flags that don't apply.
    for k in ("recon_mode", "k_hop_nb_loss", "bypass_adj_decoder",
              "estimate_adj_kwargs"):
        lk.pop(k, None)
    lk.update({
        # Two primary reconstruction objectives at parity. Both are
        # NB log-likelihood summed over 431 genes -> magnitudes ~150 nats.
        "wt_attr_reconstr":     1.0,    # NB cell
        "wt_attr_reconstr_nbr": 1.0,    # NB nbr
        # VQ-VAE commit losses are SOFT regularisers, not reconstruction
        # objectives. Original VQ-VAE paper (van den Oord 2017) uses
        # beta=0.25 and notes "results are robust to beta". We default to
        # 1.0 (slightly tighter than the paper's 0.25) but importantly NOT
        # match-magnitude with NB — that would over-constrain the encoder.
        # See response notes: equal-magnitude weighting is NOT recommended
        # in VQ-VAE literature; commit terms are intentionally smaller.
        "wt_commit_cell":       1.0,    # commit_cell
        "wt_commit_niche":      1.0,    # commit_niche
        # Adjacency BCE has small absolute magnitude (~0.5-1 nat at init,
        # bounded by log(2)) — it must be UPWEIGHTED to balance against
        # the gene-NB losses (~150 nats). Empirically `wt_adj_reconstr=1000`
        # gives the strongest spatial-niche coherence on the MERFISH/STARmap
        # MB panel without measurably hurting NB Pearson once the wide
        # codebook setup is used (k=50 macro + RVQ refinement). The
        # earlier "Pearson drop after epoch 1" symptom turned out to be
        # the codebook-size bottleneck (NB→niche-mean predictor pathology),
        # NOT the adj weight — once that's fixed via wide+RVQ, the model
        # tolerates much higher adjacency pressure.
        "wt_adj_reconstr":      1000.0,  # cosine adj BCE (1.0 -> 100 -> 25 -> 250 -> 1000)
        "edge_sampling_ratio":  2.0,
        "use_pos_weight":       True,
        "cosine_temperature":   0.1,
        # Which embedding the adjacency BCE operates on:
        #   "z_gnn"     -> continuous, NicheCompass-faithful (default)
        #   "z_q_niche" -> quantized (opt-in via _patch_dual_adj_on_zqniche)
        # See `bce_cosine_adjacency_reconstruction_loss` for the rationale.
        "adj_loss_input":       "z_gnn",
        # K-hop aggregation radius for the niche reconstruction target.
        #   1 -> mean over the cell's 1-hop spatial neighbourhood (default,
        #        legacy behaviour).
        #   2 -> mean over the 2-hop neighbourhood. Smoother targets ->
        #        the niche codebook is forced to capture larger-scale
        #        spatial structure rather than 1-hop variation. Requires
        #        the datamodule sampler to sample at least 2-hop neighbours
        #        (`num_neighbors=[8, 8]` or deeper) to be exact.
        "nbr_aggregation_hops": 1,
    })

    # The dual model doesn't yet support recon_mode-style modes (it always
    # reconstructs both branches), but downstream code reads `recon_mode`
    # from loss_kwargs in some places — set it to a no-op marker.
    lk["recon_mode"]  = "dual"

    # Monitor metric: training-loss based (as set up by the early-stopping
    # patch). Pearson-based monitors still work; default to log1p-cell since
    # the dual model produces a meaningful per-cell X_hat.
    cfg["trainer"]["monitor"] = "val_loss"

    return cfg


def _BD():
    """Shorthand: deep-copy of the dual-VQ base config."""
    return _copy(make_train_config_dualvq())


# ---------------------------------------------------------------------------
# 2d. VQNiche_Dual ablation patches
# ---------------------------------------------------------------------------

def _patch_dual_no_adj(cfg: dict) -> dict:
    """Drop the adjacency BCE loss term (test if it's load-bearing)."""
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "bce_cosine_adjacency_reconstruction_loss" in losses:
        losses.remove("bce_cosine_adjacency_reconstruction_loss")
    return cfg


def _patch_dual_no_cell_recon(cfg: dict) -> dict:
    """
    Drop the cell-branch NB loss + cell commit loss (test the niche-only
    setup; the cell decoder still runs but receives no gradient signal).
    Useful as a ceiling test for whether the cell branch helps the niche
    branch via the shared MLP trunk.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    for ln in ("nb_attribute_reconstruction_loss", "mse_commit_loss_cell"):
        if ln in losses:
            losses.remove(ln)
    return cfg


def _patch_dual_no_spatial(cfg: dict) -> dict:
    """
    Drop EVERY spatial-supervision loss term so the model trains as a
    pure cell-branch VQ-VAE + (whatever batch-integration loss is set).
    Removes:
      - nb_attribute_reconstruction_loss_nbr_dual  (niche-branch NB recon)
      - mse_commit_loss_niche                       (niche VQ commit)
      - bce_cosine_adjacency_reconstruction_loss    (adjacency BCE)

    The niche-side modules (GNN, vq_niche, niche decoder, adjacency
    decoder) are still instantiated by the model and run forward, but
    receive zero gradient signal — they're effectively idle. This is
    the DIAGNOSTIC variant for the hypothesis "spatial losses are
    pulling the cell encoder away from cell-type-discriminative features".
    Under this patch, training conditions match scVI / Harmony shape:
    pure cell-NB + cell-commit + adversarial/MMD batch integration.

    Sibling of `_patch_dual_no_adj` (drops only adjacency) and
    `_patch_dual_no_cell_recon` (drops only cell-side). When all three
    are needed together for ablations, apply this LAST so the niche
    losses get removed regardless of order.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    for ln in (
        "nb_attribute_reconstruction_loss_nbr_dual",
        "nb_attribute_reconstruction_loss_nbr",   # legacy single-codebook name
        "mse_commit_loss_niche",
        "bce_cosine_adjacency_reconstruction_loss",
        # The vanilla (non-dual) adjacency-BCE name, in case earlier patches
        # left it in the loss list.
        "bce_adjacency_reconstruction_loss",
    ):
        if ln in losses:
            losses.remove(ln)
    return cfg


def _patch_dual_no_cell_nb(cfg: dict) -> dict:
    """
    Drop ONLY the cell-branch NB reconstruction loss
    (`nb_attribute_reconstruction_loss`). The cell commit loss
    (`mse_commit_loss_cell`) STAYS — so the cell-VQ still commits to
    its codebook and EMA updates continue normally.

    Difference from `_patch_dual_no_cell_recon`
    ------------------------------------------
    `_patch_dual_no_cell_recon` removes BOTH the cell-NB and the cell-
    commit loss; under that patch the cell-VQ has no gradient signal
    at all (encoder isn't pulled toward codebook, codebook still
    updates via EMA from whatever z_mlp happens to be). This patch
    is more surgical: it removes ONLY the cell-NB while keeping the
    encoder→nearest-code commit pressure intact.

    Intended use: diagnostic when paired with the LEGACY SHARED-MLP
    trunk (i.e. NO `+decoupled-enc`). Under that configuration
    `z_mlp` is shaped by:
      - cell-commit  (pulls z_mlp toward nearest cell codebook entry)
      - nbr-NB       (via the same shared trunk, fed into the GNN)
      - niche-commit (via the GNN path)
      - adjacency-BCE (on z_gnn, niche-side)

    If `cell_code_indices[level_0]` NMI is still high under this
    setting, the spatial losses on the shared trunk are doing the
    cell-type discrimination — the cell-NB term was only ever
    decorating a partition that the niche-side gradients already
    aligned with cell types via the shared `z_mlp`. If it crashes,
    cell-NB was load-bearing for cell-NMI.

    Sibling of `_patch_dual_no_cell_recon` (drops both terms) and
    `_patch_dual_no_recon` (drops every reconstruction term, keeps
    both commits).
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "nb_attribute_reconstruction_loss" in losses:
        losses.remove("nb_attribute_reconstruction_loss")
    return cfg


def _patch_dual_no_recon(cfg: dict) -> dict:
    """
    Drop ALL reconstruction losses (cell-NB + nbr-NB + adjacency-BCE)
    while keeping the commit losses alive. The encoder still receives
    gradient signal — but ONLY from the VQ commit term that pulls
    `z_mlp` toward its nearest codebook entry. The codebook still
    updates via EMA from whatever `z_mlp` samples are assigned to
    each code.

    Intended use: a NEGATIVE TEST for the architectural-leakage
    hypothesis.

    Reasoning
    ---------
    After s41–s43 the architecture is strictly decoupled (no parameter
    shared between the cell and niche branches downstream of the input
    tensor). If cell-NMI did NOT improve under that decoupling, the
    leakage hypothesis is wrong and the cell-NMI ceiling is set by one
    of:
      (1) codebook K₁ is too small vs cell-type cardinality,
      (2) the NB-reconstruction objective doesn't isolate cell-type
          identity (it also encodes state / depth / within-type
          variation),
      (3) k-means init on the *raw* z_mlp dominates, with EMA unable
          to escape the basin.

    Stripping reconstruction discriminates (3) from (1+2):
      - cell-NMI similar to the best s43 run -> structure is driven by
        k-means init / data geometry, NOT reconstruction. The codebook
        finds the same partition with or without NB pressure.
      - cell-NMI crashes to baseline -> reconstruction IS the driver,
        we're at its resolution ceiling, and the next move is K₁ ↑ or
        a fundamentally different objective (contrastive, code-
        orthogonality, etc.).

    What stays alive
    ----------------
      - mse_commit_loss_cell   (encoder -> nearest cell codebook entry)
      - mse_commit_loss_niche  (z_gnn -> nearest niche codebook entry)
      - EMA codebook updates (these are NOT gradient-based — they fire
        every step regardless of which losses are in the loss list)

    What goes
    ---------
      - nb_attribute_reconstruction_loss              (cell NB)
      - nb_attribute_reconstruction_loss_nbr_dual     (nbr NB)
      - nb_attribute_reconstruction_loss_nbr          (legacy single-codebook nbr NB)
      - bce_cosine_adjacency_reconstruction_loss      (adjacency BCE on z_gnn)
      - bce_adjacency_reconstruction_loss             (legacy single-codebook adj-BCE)

    Apply LAST in the patch chain so no later patch re-adds a recon
    loss name (none of the current patches do this, but conventional
    safety).
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    for ln in (
        "nb_attribute_reconstruction_loss",
        "nb_attribute_reconstruction_loss_nbr_dual",
        "nb_attribute_reconstruction_loss_nbr",
        "bce_cosine_adjacency_reconstruction_loss",
        "bce_adjacency_reconstruction_loss",
    ):
        if ln in losses:
            losses.remove(ln)
    return cfg


def _patch_dual_batch_lr(
        cfg: dict,
        batch_size: Optional[int] = None,
        lr: Optional[float] = None,
    ) -> dict:
    """
    Override `loader_params.batch_size` and/or `optimizer_params.lr` in
    the resolved config. Designed for ablation sweeps that BAKE a
    specific (batch, lr) pair into a variant key — different from the
    multiseed `--batch-size` / `--lr` CLI flags, which override at
    submission time without changing the variant identity.

    Either kwarg can be None to leave that knob untouched.

    Recommended pairings (matches the docstring on `submit_multi_seed.sh`):

      batch_size  | sqrt-scaled lr | linear-scaled lr
      ------------+----------------+------------------
       256 (def)  | 5e-4           | 5e-4
       512        | ~7e-4          | 1e-3
      1024        | 1e-3           | 2e-3
      2048        | ~1.4e-3        | 4e-3
      4096        | 2e-3           | 8e-3

    Sqrt-scaling is the safer starting point — linear can saturate the
    adversarial discriminator and collapse the encoder at 8x-16x batch.
    """
    if batch_size is not None:
        cfg["datamodule"]["loader_params"]["batch_size"] = int(batch_size)
    if lr is not None:
        cfg["model"]["optimizer_params"]["lr"] = float(lr)
    return cfg


def _patch_dual_no_batch_int(cfg: dict) -> dict:
    """
    Drop EVERY batch-integration loss (adversarial CE + MMD-batch +
    MMD-prior). The cell-side encoder + decoders + VQ codebooks still
    train normally; no explicit batch-correction signal is applied.
    Useful for testing whether SQUINT's per-batch decoder-covariate
    (`+decoder-cov`) is enough to handle batch differences on its own,
    without an encoder-side correction.

    Removes:
      - `adversarial_batch_loss`               (current adv-GRL name)
      - `adversarial_cross_entropy_batch_loss` (legacy adv-GRL name)
      - `mmd_batch_loss`                       (pairwise per-batch MMD)
      - `mmd_prior_loss`                       (MMD against isotropic prior)
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    for ln in (
        "adversarial_batch_loss",
        "adversarial_cross_entropy_batch_loss",
        "mmd_batch_loss",
        "mmd_prior_loss",
    ):
        if ln in losses:
            losses.remove(ln)
    # Also disable the adversarial classifier head + GRL alpha so the
    # head isn't built into the model graph at all (otherwise it
    # consumes optimizer state and forward-pass time for nothing).
    cfg["model"]["adversarial_batch_dim_request"] = False
    cfg["model"]["adversarial_alpha"] = 0.0
    return cfg


def _patch_dual_no_encoder_film(cfg: dict) -> dict:
    """
    Disable the ENCODER-SIDE FiLM (`conditioning_module`) by removing
    its `condition_list`. The decoders' FiLM modules are left alive —
    each decoder owns its own FiLM instance — and `+decoder-cov` still
    threads the batch one-hot through the decoder inputs.

    Why this matters specifically for `+decoupled-enc`
    --------------------------------------------------
    The encoder's `conditioning_module` is a SINGLE FiLM instance that
    is called on BOTH `z_mlp_cell_path` and `z_mlp_niche_path` (see
    `vqniche_dual_encoder.py`, lines ~382 + ~410). Its affine MLP
    therefore receives gradients from cell-side losses AND every
    spatial loss in the niche path. Even when the cell and niche MLP
    trunks are fully decoupled via `niche_mlp_params`, the FiLM update
    driven by spatial gradients re-enters the cell path on the next
    forward — a backdoor that defeats the point of decoupling.

    This patch shuts that backdoor by removing `condition_list` from
    `encoder_params.conditioning_params`. The encoder build then takes
    the `else` branch at `vqniche_dual_encoder.py` line 309 and sets
    `self.conditioning_module = None`, so no FiLM module is ever
    instantiated on the encoder side.

    Use this WITH `+decoupled-enc` (or `+shared-specific-enc`) to get
    the strict architectural decoupling you intuited; using it on a
    legacy single-trunk variant just drops FiLM with no other effect.

    No-op if the cfg has no encoder `conditioning_params` to begin
    with.
    """
    enc = cfg["model"]["encoder_params"]
    cp = enc.get("conditioning_params")
    if not cp:
        return cfg
    # Remove just `condition_list` (the key the encoder checks at build
    # time, `vqniche_dual_encoder.py:300`). Keep the rest of the dict
    # so any downstream consumer that snapshots the cfg sees a sensible
    # record of "FiLM was configured but disabled".
    cp.pop("condition_list", None)
    return cfg


def _patch_dual_niche_neck(
        cfg: dict,
        hidden_channels: Optional[List[int]] = None,
        dropout: float = 0.0,
        norm: Optional[str] = None,
    ) -> dict:
    """
    Insert a niche-side neck MLP between `z_mlp` and the GNN. The
    cell-VQ still consumes `z_mlp` directly; only the GNN input is
    routed through this extra MLP. See the `VQNiche_Dual_Encoder`
    docstring for the schematic.

    Why this might help:
      - Currently the cell branch shares `z_mlp` with the niche-side
        GNN input. Niche-side gradients (adjacency BCE, nbr-NB,
        niche-commit) all flow back into `z_mlp`, which can pull the
        cell quantiser away from cell-type-discriminative geometry.
      - Inserting a learned linear transformation between `z_mlp` and
        the GNN lets the niche-side gradients shape that new tensor
        independently, leaving `z_mlp` (and therefore the cell-VQ
        input) cleaner.

    Default `hidden_channels=[256]` → a single 256-d projection layer
    that preserves the wide-spine latent dim. Pass `[128]` etc. for a
    smaller / different output dim (the GNN will be sized accordingly).
    """
    target = list(hidden_channels) if hidden_channels else [256]
    cfg["model"]["encoder_params"]["niche_neck_params"] = {
        "hidden_channels": target,
        "dropout":          float(dropout),
        "act":              "relu",
        "norm":             norm,
    }
    return cfg


def _patch_dual_decoupled_encoders(
        cfg: dict,
        niche_mlp_params: Optional[dict] = None,
    ) -> dict:
    """
    Decouple the niche-branch encoder from the cell-branch encoder by
    building a SEPARATE niche-side MLP module (independent weights).

    Default architecture (legacy, when this patch is NOT applied):

        x  ─►  shared MLP  ─►  z_mlp ─┬─► VQ_cell  (cell branch)
                                       └─► [niche_neck?] ─► GNN ─► VQ_niche

    Spatial-loss gradients (adjacency BCE, nbr-NB, niche-commit) flow
    through the GNN, into `z_mlp`, and update the SHARED MLP's weights
    — which ALSO produces the input to VQ_cell. The cell-VQ input is
    therefore gradient-coupled to the spatial losses and the cell
    codebook can end up encoding spatial / neighbourhood information
    rather than purely cell-intrinsic signal.

    After this patch:

        x ─┬─► MLP_cell   ─► z_mlp_cell  ─► VQ_cell  (cell branch)
           │
           └─► MLP_niche  ─► z_mlp_niche ─► [niche_neck?] ─► GNN ─► VQ_niche

    `MLP_cell` and `MLP_niche` have INDEPENDENT weights. Spatial-loss
    gradients update `MLP_niche.weight` only — the cell-side MLP is
    structurally shielded.

    Parameters
    ----------
    niche_mlp_params : dict, optional
        Architecture for the new niche-side MLP. When `None` (the
        default), uses a deep copy of `cfg['model']['encoder_params']
        ['mlp_params']` — i.e. the niche MLP has the same shape as
        the cell-side MLP, just independent weights. Pass an explicit
        dict to give the niche side a different architecture.
        IMPORTANT: keep `niche_mlp_params['hidden_channels'][-1]`
        equal to the cell-side `mlp_params['hidden_channels'][-1]`
        if FiLM batch correction is enabled (FiLM shares one module
        across both paths).

    Use cases
    ---------
      - Cell-NMI is dragged down by spatial information bleeding into
        the cell codes (the canonical scenario for this knob).
      - You want a fair test of whether the dual-VQ architecture's
        cell branch is intrinsically cell-type-discriminative — this
        is the cleanest "cell branch sees no spatial gradient" setup.

    Caveats
    -------
      - Doubles the encoder MLP parameter count (roughly).
      - Niche-side per-sample compute roughly doubles too (one extra
        MLP pass per training step).
      - Compatible with `_patch_dual_niche_neck` — the niche_neck is
        applied AFTER the new niche MLP, so the full niche path is
        `x -> MLP_niche -> niche_neck -> GNN`.
    """
    enc = cfg["model"]["encoder_params"]
    if niche_mlp_params is None:
        niche_mlp_params = _copy(enc.get("mlp_params", {})) or {}
    enc["niche_mlp_params"] = niche_mlp_params
    return cfg


def _patch_dual_coupled_encoders(cfg: dict) -> dict:
    """Force the COUPLED (shared-trunk) encoder — the INVERSE of
    `_patch_dual_decoupled_encoders` / `_patch_dual_shared_specific_encoders`.
    Removes the separate niche-side MLP (`niche_mlp_params`) and any Y-shape
    shared trunk (`shared_mlp_params`) so the cell and niche branches share a
    single MLP trunk (the legacy default). Spatial-loss gradients then flow back
    into the cell-VQ input — the coupling this ablation tests. Apply OUTERMOST on
    a build that has decoupled / shared-specific encoders (e.g. the s55_v3 spine).
    """
    enc = cfg["model"]["encoder_params"]
    enc.pop("niche_mlp_params", None)
    enc.pop("shared_mlp_params", None)
    return cfg


def _patch_dual_shared_specific_encoders(
        cfg: dict,
        shared_mlp_params: Optional[dict] = None,
        path_mlp_params: Optional[dict] = None,
        shared_last_dim: Optional[int] = None,
        path_last_dim: Optional[int] = None,
    ) -> dict:
    """
    Y-shape encoder architecture — one SHARED MLP + one PATH-SPECIFIC
    MLP per branch, with the shared output CONCATENATED into each
    path's downstream input.

    Architecture:

        x ─┬─►  MLP_shared  ─►  z_shared ────────────┐
           │                                         │ concat
           ├─►  MLP_cell    ─►  z_path_cell    ─► z_mlp_cell ─► VQ_cell
           │
           └─►  MLP_niche   ─►  z_path_niche   ─► z_mlp_niche ─► GNN ─► VQ_niche
                                                  ▲
                                          (concat with z_shared)

    Gradient routing:
      - Shared MLP receives gradients from BOTH branches (cell-NB +
        cell-commit AND spatial-adj + nbr-NB + niche-commit).
        Feature reuse happens here.
      - Cell-path MLP receives ONLY cell-side gradients (no spatial
        leakage).
      - Niche-path MLP receives ONLY niche-side gradients.

    Compared to the existing encoder modes on this codebase:
      - Legacy (only `mlp_params` in cfg): single shared MLP — full
        spatial-gradient leakage into the cell-VQ input.
      - Decoupled (`_patch_dual_decoupled_encoders`): TWO independent
        MLPs — full gradient isolation but no feature reuse.
      - Y-shape (this helper): THREE MLPs — shared core + two
        specialised paths. The cell-path MLP weights are insulated
        from spatial gradients; the shared trunk's weights are NOT
        (they see gradients from both branches).

    Default sizing
    --------------
    By default the helper HALVES the last layer dim of the cfg's
    `mlp_params` and uses that for all three MLPs:

        mlp_params (in cfg) = {hidden_channels: [400, 400, 256], ...}
                            ↓
        shared_mlp_params   = {hidden_channels: [400, 400, 128], ...}
        path_mlp_params     = {hidden_channels: [400, 400, 128], ...}

    Effective downstream dims stay at the original 256:
      - VQ_cell input  = 128 (shared) + 128 (cell-path) = 256
      - GNN input      = 128 (shared) + 128 (niche-path) = 256

    so codebook embedding dims, GNN config, and decoder shapes are
    UNCHANGED relative to the legacy shared-trunk variant.

    Parameters
    ----------
    shared_mlp_params : dict, optional
        Architecture for the shared trunk. `None` -> half-dim deep
        copy of `cfg['model']['encoder_params']['mlp_params']`.
    path_mlp_params : dict, optional
        Architecture for EACH of the two path-specific MLPs (cell
        and niche). The two paths share the SHAPE (this dict) but
        get INDEPENDENT WEIGHTS. `None` -> half-dim deep copy of
        the cfg's `mlp_params`.

    Use cases
    ---------
      - Cell-NMI is dragged by spatial information leaking into z_mlp
        but you want SOME shared feature reuse for parameter
        efficiency. This is the balanced fix.
      - You expect the cell + niche branches to share low-level
        features (e.g. raw gene-expression pattern recognition) but
        diverge in the higher-level abstraction toward each branch's
        own discrimination target.

    Caveats
    -------
      - Increases the encoder MLP parameter count by ~50% (three
        MLPs vs one). Compute scales similarly.
      - The shared trunk is STILL gradient-coupled to spatial losses.
        If your goal is FULL gradient isolation of the cell branch
        from spatial pulls, use `_patch_dual_decoupled_encoders`
        instead.
    """
    import copy as _cp
    enc = cfg["model"]["encoder_params"]
    base_mlp = _cp.deepcopy(enc.get("mlp_params", {}))

    def _halve_last(mlp_cfg: dict) -> dict:
        """Return a deep copy of `mlp_cfg` with its last hidden
        layer dim halved. No-op if `hidden_channels` is absent."""
        out = _cp.deepcopy(mlp_cfg)
        h = out.get("hidden_channels")
        if h:
            h = list(h)
            h[-1] = max(1, h[-1] // 2)
            out["hidden_channels"] = h
        return out

    def _override_last(mlp_cfg: dict, last_dim: int) -> dict:
        """Return a deep copy of `mlp_cfg` with its last hidden layer
        dim replaced by `last_dim`. No-op if `hidden_channels` is
        absent."""
        out = _cp.deepcopy(mlp_cfg)
        h = out.get("hidden_channels")
        if h:
            h = list(h)
            h[-1] = int(last_dim)
            out["hidden_channels"] = h
        return out

    if shared_mlp_params is None:
        shared_mlp_params = _halve_last(base_mlp)
    if path_mlp_params is None:
        path_mlp_params = _halve_last(base_mlp)

    # Shortcut overrides — apply AFTER the default fallback so callers
    # can pass just `shared_last_dim=` / `path_last_dim=` to vary the
    # bottleneck while keeping the trunk shape inherited from the cfg.
    if shared_last_dim is not None:
        shared_mlp_params = _override_last(shared_mlp_params, shared_last_dim)
    if path_last_dim is not None:
        path_mlp_params = _override_last(path_mlp_params, path_last_dim)

    enc["shared_mlp_params"] = shared_mlp_params
    enc["mlp_params"] = _cp.deepcopy(path_mlp_params)       # cell-path MLP
    enc["niche_mlp_params"] = _cp.deepcopy(path_mlp_params) # niche-path MLP
    return cfg


def _patch_dual_no_nbr_recon(cfg: dict) -> dict:
    """
    Drop ONLY the neighborhood-gene-expression NB reconstruction loss
    (`nb_attribute_reconstruction_loss_nbr_dual`). The niche encoder
    still runs and is still committed to its codebook (niche-commit
    kept), and the adjacency-BCE loss is still active — so the niche
    branch retains spatial-structure supervision via the adjacency
    decoder, but no longer tries to reconstruct neighborhood gene
    expression.

    Use this together with `_patch_dual_no_adj` to form a 2x2 grid
    that isolates the contribution of each spatial loss term to
    downstream cell-type / niche-type NMI:
       adj=ON,  nbr=ON   -> baseline
       adj=OFF, nbr=ON   -> `_patch_dual_no_adj`
       adj=ON,  nbr=OFF  -> `_patch_dual_no_nbr_recon` (this)
       adj=OFF, nbr=OFF  -> `_patch_dual_no_spatial`

    Sibling of `_patch_dual_no_adj` and `_patch_dual_no_spatial`.
    Apply LAST in the patch chain so the loss removal isn't undone
    by a later patch that re-adds the loss name.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    for ln in (
        "nb_attribute_reconstruction_loss_nbr_dual",
        "nb_attribute_reconstruction_loss_nbr",   # legacy single-codebook name
    ):
        if ln in losses:
            losses.remove(ln)
    return cfg


def _patch_dual_rvq(cfg: dict,
                    branch: str = "both",
                    codebook_sizes=(30, 200)) -> dict:
    """
    Swap one or both VQ slots for ResidualVQ_Squint. `branch` may be
    'cell', 'niche', or 'both'.
    """
    if branch in ("cell", "both"):
        cfg["model"]["encoder_params"]["vq_cell_params"]  = _default_rvq_params(codebook_sizes)
    if branch in ("niche", "both"):
        cfg["model"]["encoder_params"]["vq_niche_params"] = _default_rvq_params(codebook_sizes)
    return cfg


def _patch_dual_vq(cfg: dict,
                   branch: str = "cell",
                   codebook_size: int = 30) -> dict:
    """
    Swap one or both VQ slots for a single-level (non-hierarchical)
    `VectorQuantize` with the specified codebook_size. Mirrors
    `_patch_dual_rvq` but for the single-level case — useful for v7
    ablations that hold one branch at a non-hierarchical VQ while the
    other uses RVQ. `branch` may be 'cell', 'niche', or 'both'.
    """
    if branch in ("cell", "both"):
        cfg["model"]["encoder_params"]["vq_cell_params"]  = _default_vq_params(codebook_size=codebook_size)
    if branch in ("niche", "both"):
        cfg["model"]["encoder_params"]["vq_niche_params"] = _default_vq_params(codebook_size=codebook_size)
    return cfg


def _patch_dual_cvq(cfg: dict,
                    branch: str = "both",
                    k1: int = 30,
                    k2: int = 10,
                    k3: Optional[int] = None) -> dict:
    """
    Swap one or both VQ slots for ConditionalVQ (tree-structured VQ).

    `k3=None` -> legacy 2-level CVQ (K1 macro × K2 sub-children).
    `k3=<int>` -> 3-level CVQ (K1 × K2 × K3 distinct codes), with one
    leaf VQ of size K3 per (l1, l2) bucket. The leaf forward pass and
    extra residual STE are wired inside `ConditionalVQ.forward`.
    """
    if branch in ("cell", "both"):
        cfg["model"]["encoder_params"]["vq_cell_params"]  = _default_cvq_params(k1, k2, k3)
    if branch in ("niche", "both"):
        cfg["model"]["encoder_params"]["vq_niche_params"] = _default_cvq_params(k1, k2, k3)
    return cfg


def _patch_dual_gatv2(cfg: dict) -> dict:
    """Switch the GNN encoder from SAGE to GATv2 (still 1 layer)."""
    cfg["model"]["encoder_params"]["gnn_name"] = "GATv2Conv"
    return cfg


def _patch_dual_adj_weight(cfg: dict, weight: float) -> dict:
    """Override the adjacency BCE weight (default in the dual base is 250)."""
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_adj_reconstr"] = float(weight)
    return cfg


def _patch_dual_attr_recon_weight(cfg: dict, weight: float) -> dict:
    """
    Override the CELL-branch NB attribute-reconstruction weight
    (`wt_attr_reconstr` in `loss_kwargs`; default 1.0).

    Lowering this weight loosens how tightly the cell embedding is
    anchored to per-batch gene means → opens room for batch-invariance
    signals (adversarial / MMD) to move the cell embedding around →
    can lift cell_iLISI at the cost of cell-branch NB reconstruction
    quality. Raising it does the opposite. See `_patch_dual_attr_recon_nbr_weight`
    for the niche-branch sibling.
    """
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_attr_reconstr"] = float(weight)
    return cfg


def _patch_dual_attr_recon_nbr_weight(cfg: dict, weight: float) -> dict:
    """
    Override the NICHE-branch NB attribute-reconstruction weight
    (`wt_attr_reconstr_nbr` in `loss_kwargs`; default 1.0).

    The niche NB term reconstructs the K-hop neighbourhood-mean gene
    expression from `z_q_niche`. At weight=1.0 this is the dominant
    pull on the niche embedding alongside the cosine adjacency BCE
    (`wt_adj_reconstr=1000`) — both anchor the niche embedding to
    per-batch gene statistics, which fights batch integration on the
    neighborhood embedding (low nbr_iLISI).

    Lowering this weight is the easiest way to free `z_gnn` /
    `z_q_niche` for batch integration without disabling the niche
    reconstruction entirely (which `_patch_dual_no_nbr_recon` would
    do, dropping nbr_NMI hard — see s19_v3 in the historic results).

    Use cases:
      - weight=0.3-0.5: aggressive — niche embedding can integrate
        more freely, expect nbr_iLISI to rise. Watch nbr_NMI: too
        low and niche structure collapses (like s19_v3 at weight=0).
      - weight=2.0+: tighter anchor — niche embedding stays close to
        per-batch gene means, nbr_iLISI suffers further.
    """
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_attr_reconstr_nbr"] = float(weight)
    return cfg


def _patch_dual_codebook_orth_reg(
        cfg: dict,
        wt_codebook_orthogonal_regularization: float = 0.2,
    ) -> dict:
    """
    Add `l2_codebook_orthogonal_regularization_loss` to the loss
    dispatcher, regularising the CELL-BRANCH level-1 codebook toward
    mutually-orthogonal codes.

    The loss reads `codebook_embeddings` from `loss_data` (populated
    by `VQNiche_Dual._step` to point at the cell-branch L1 codebook).
    It computes pairwise cosine similarity between codes and penalises
    high off-diagonal similarity → codes get pushed apart in the
    embedding space.

    Why this can lift cell-NMI: NMI rewards cluster separation. The
    NB-reconstruction loss alone doesn't directly constrain inter-code
    distances; it only cares that each cell's nearest code reproduces
    its expression. With small codebooks (e.g. cell L1 = 15–30), two
    codes can drift close together → cells flip ambiguously between
    them → cluster purity drops → NMI drops. Orth-reg keeps codes
    well-separated by construction.

    Parameters
    ----------
    wt_codebook_orthogonal_regularization
        Loss weight. Default 0.2; 0.1–0.5 is the useful range. The
        un-weighted loss is in [0, 1] (it's cosine-similarity-squared
        minus 1/n_codes), so wt=0.2 keeps it on a comparable scale to
        the cell-NB term (~0.5–1 nat).
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "l2_codebook_orthogonal_regularization_loss" not in losses:
        losses.append("l2_codebook_orthogonal_regularization_loss")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_codebook_orthogonal_regularization"] = float(
        wt_codebook_orthogonal_regularization
    )
    return cfg


def _patch_dual_contrastive_cell(
        cfg: dict,
        wt_contrastive_cell: float = 1.0,
        k_pos: int = 5,
        temperature: float = 0.1,
        log_transform_gene_space: bool = True,
    ) -> dict:
    """
    Add the NT-Xent contrastive auxiliary loss on the pre-quantization
    cell-branch latent (`contrastive_cell_attribute_loss`).

    The loss reads `quantizer_input_cell` (= z_mlp_cell of seed cells)
    and `target_attr` (= raw counts of seed cells) from `loss_data`.
    For each anchor cell it picks the top-`k_pos` other cells in the
    batch with the most similar log1p gene-expression profile as
    positive pairs, then runs NT-Xent in cosine-similarity space at
    `temperature`. This pulls same-type cells together in z_mlp space
    and pushes different-type apart — an explicit between-cell
    objective that complements NB's within-cell objective.

    Rationale (per the s44 negative-test result + s46 weight-escalation
    plateau): NB reconstruction at any weight saturates cell-NMI around
    the level achievable from "data-structure k-means", because NB
    optimises per-cell rate prediction, not between-cell cluster
    separation. The contrastive loss directly optimises the latter.

    Parameters
    ----------
    wt_contrastive_cell : float
        Loss weight. 0.5-2.0 is the useful range; 1.0 matches the
        scale of cell-NB at its default weight (~0.5-1.0 nat).
    k_pos : int
        Number of positive pairs per anchor (top-k nearest neighbours
        in log1p gene-expression cosine similarity). 3-10 is sensible
        for spatial transcriptomics; 5 is a good default.
    temperature : float
        NT-Xent softmax temperature. SimCLR convention is 0.1. Smaller
        -> sharper attraction / repulsion.
    log_transform_gene_space : bool
        Whether to log1p the raw counts before computing pair
        similarities. Strongly recommended (raw counts have huge
        dynamic range; a few highly-expressed genes dominate cosine
        similarity without log1p).
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "contrastive_cell_attribute_loss" not in losses:
        losses.append("contrastive_cell_attribute_loss")
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["wt_contrastive_cell"]       = float(wt_contrastive_cell)
    lk["k_pos"]                     = int(k_pos)
    lk["temperature"]               = float(temperature)
    lk["log_transform_gene_space"]  = bool(log_transform_gene_space)
    return cfg


def _patch_dual_contrastive_cell_within_batch(
        cfg: dict,
        wt_contrastive_cell: float = 1.0,
        k_pos: int = 5,
        temperature: float = 0.1,
        log_transform_gene_space: bool = True,
    ) -> dict:
    """
    Within-batch variant of `_patch_dual_contrastive_cell`. Adds the
    `contrastive_cell_attribute_within_batch_loss` to the loss list —
    same NT-Xent formulation as the global variant, but BOTH positive-
    pair candidates AND the NT-Xent denominator are restricted to
    cells sharing the anchor's `adata_batch_id` (== same MERFISH /
    STARmap section, etc.).

    Why use this over the global variant
    ------------------------------------
    Mirrors `adj_within_section_only=True` on the cosine adjacency
    BCE. Without the restriction, the global NT-Xent denominator
    includes cross-section pairs and its gradient pushes
    biologically-similar cells from different sections APART — which
    directly counters the batch-integration objective that the
    decoder-side batch covariate (`+decoder-cov`) and the spatial-
    graph training are trying to achieve. With the restriction,
    cross-section pairs are unpressured (neither pulled together nor
    pushed apart) and the encoder is left free to learn a batch-
    invariant cluster geometry without being fought against by this
    auxiliary loss.

    Numerical correctness was validated on a 5-test suite covering
    (i) finite/non-negative loss on aligned input, (ii) combined loss
    == average of per-batch losses (no cross-batch leakage in the
    forward), (iii) singleton-batch anchors contribute 0, (iv) batch
    1's z does NOT enter batch 0 anchors' gradients, (v) hand-
    computed tiny case agrees with expected magnitude.

    Parameters (same semantics as `_patch_dual_contrastive_cell`)
    ----------
    wt_contrastive_cell : float
        Loss weight. With B=512 split across 2 sections (~256 each),
        the per-anchor contrastive term is bounded by log(256) ≈ 5.5
        nats — comparable to cell-NB at its default weight=1 mass per
        cell summed over genes (~0.5-1 nat). Practical sweep range
        spans 1-1000.
    k_pos, temperature, log_transform_gene_space :
        Identical to the global variant.

    Requires
    --------
    `loss_data['node_adata_batch_ids']` must be populated by the
    model's `_step` (it is, unconditionally, in `VQNiche_Dual._step`).
    If absent the loss raises rather than silently falling back to
    the global behaviour.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "contrastive_cell_attribute_within_batch_loss" not in losses:
        losses.append("contrastive_cell_attribute_within_batch_loss")
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["wt_contrastive_cell"]       = float(wt_contrastive_cell)
    lk["k_pos"]                     = int(k_pos)
    lk["temperature"]               = float(temperature)
    lk["log_transform_gene_space"]  = bool(log_transform_gene_space)
    return cfg


def _patch_dual_codebook_diversity(
        cfg: dict,
        weight: float = 1.0,
        temperature: float = 100.0,
        branch: str = "cell",
    ) -> dict:
    """
    Enable lucidrains' codebook-diversity loss on the VQ codebook(s).
    The loss is computed INSIDE the VQ module on every forward pass:
    it takes the cosine-similarity matrix of the codes, applies a
    softmax at `temperature`, and penalises the resulting entropy
    being far from uniform — effectively a SwAV-style repulsion that
    keeps codes spread out on the embedding sphere.

    For ResidualVQ_Squint this applies to EVERY level (L1 + L2 + ...)
    with the same weight + temperature. Per-level tuning isn't worth
    the complexity given a 2-level RVQ.

    Parameters
    ----------
    weight : float
        Diversity loss weight. 0.1-10 is the useful range; 1.0 keeps
        the term comparable in scale to the NB-cell loss (~0.5-1 nat).
        Lucidrains' implementation adds it inside the VQ module's own
        `forward` return value, where it joins the commit loss list.
    temperature : float
        Softmax temperature on the within-codebook similarity matrix
        before computing the diversity term. Larger T -> softer
        repulsion across more code pairs; smaller T -> sharper, focuses
        on the most-similar pairs. 100.0 (lucidrains default) works
        well for codebook sizes 30-200.
    branch : 'cell' | 'niche' | 'both'
        Which VQ slot(s) to apply the diversity loss to.

    Mechanism
    ---------
    Sets `codebook_diversity_loss_weight` and
    `codebook_diversity_temperature` in `vq_cell_params` /
    `vq_niche_params`. `ResidualVQ_Squint.__init__` plumbs these
    through to every inner `VectorQuantize` module.
    """
    if branch not in ("cell", "niche", "both"):
        raise ValueError(f"branch must be 'cell'/'niche'/'both', got {branch!r}")
    enc = cfg["model"]["encoder_params"]
    if branch in ("cell", "both"):
        enc["vq_cell_params"]["codebook_diversity_loss_weight"]  = float(weight)
        enc["vq_cell_params"]["codebook_diversity_temperature"]  = float(temperature)
    if branch in ("niche", "both"):
        enc["vq_niche_params"]["codebook_diversity_loss_weight"] = float(weight)
        enc["vq_niche_params"]["codebook_diversity_temperature"] = float(temperature)
    return cfg


def _patch_dual_continuous_vq(cfg: dict, branch: str = "both") -> dict:
    """
    Replace the discrete VQ bottleneck with a CONTINUOUS passthrough
    (`ContinuousVQ`) on the cell and/or niche branch.

    This is the discretization ABLATION (addresses the reviewer comment that
    "the rationale for using discrete codebooks over continuous latents is
    not sufficiently supported"). It isolates whether the *discreteness* of
    the codebook — not the encoder/decoder capacity, depth, or any other
    architectural choice — drives SQUINT's benchmark gain.

    The encoder/decoder architecture, latent dimensionality, graph, sampler,
    and every non-VQ loss are left EXACTLY as-is; only the quantizer module
    is swapped for an identity map. Concretely, with `branch="both"`:
      - z_q = z  (the continuous encoder latent flows straight to the decoder,
        no nearest-codebook snap);
      - the commitment loss `mse_commit_loss = MSE(z, z_q) == 0`;
      - the codebook-diversity term is dropped (there is no codebook).

    "Comparable capacity": the continuous latent has the SAME dimensionality
    as the VQ embedding dim (the VQ quantizes in-place, so swapping it for an
    identity map changes neither the latent dim nor the decoder input shape).
    The continuous variant therefore has >= the representational capacity of
    the discrete one — the fair, conservative comparison the reviewer asks
    for (if discrete still matches/wins despite the continuous model having
    strictly more capacity, discretization is doing real work).

    Apply this OUTERMOST in a build chain so it owns the final
    `vq_*_params`, overriding any RVQ / codebook-diversity settings set by
    inner patches. That way the continuous build can be written as the exact
    discrete build wrapped in one call — self-evidently "same architecture,
    continuous bottleneck".

    Parameters
    ----------
    branch : 'cell' | 'niche' | 'both'
        Which VQ slot(s) to make continuous. The full "no VQ-VAE" ablation
        uses 'both'.
    """
    if branch not in ("cell", "niche", "both"):
        raise ValueError(f"branch must be 'cell'/'niche'/'both', got {branch!r}")
    enc = cfg["model"]["encoder_params"]
    if branch in ("cell", "both"):
        enc["vq_cell_params"] = {"vq_name": "ContinuousVQ"}
    if branch in ("niche", "both"):
        enc["vq_niche_params"] = {"vq_name": "ContinuousVQ"}
    return cfg


def _patch_dual_contrastive_cross_batch(
        cfg: dict,
        wt_cross: float = 1.0,
        k_cross: int = 1,
        mnn_floor: float = 0.0,
        mutual: bool = True,
    ) -> dict:
    """
    Swap the within-batch contrastive cell loss for its CROSS-BATCH MNN
    variant (`contrastive_cell_attribute_cross_batch_mnn_loss`): the
    within-batch NT-Xent is kept UNCHANGED (resolution) and a cross-batch
    mutual-nearest-neighbour PURE-ATTRACTION term is added (integration) —
    it pulls the most-similar cells across sections together with NO
    negatives, so it never repels cross-section cells (the failure mode that
    makes the within-batch loss hurt iLISI/MMD).

    Apply OUTERMOST on a build that already carries the within-batch
    contrastive loss (e.g. the s49_v23 spine): the within-batch kwargs
    (wt_contrastive_cell, k_pos, temperature) are inherited and the cross
    kwargs are added. `wt_cross=0` behaves exactly like the within-batch loss.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "contrastive_cell_attribute_within_batch_loss" in losses:
        losses.remove("contrastive_cell_attribute_within_batch_loss")
    if "contrastive_cell_attribute_cross_batch_mnn_loss" not in losses:
        losses.append("contrastive_cell_attribute_cross_batch_mnn_loss")
    lk = cfg["model"]["loss_params"]["loss_kwargs"]
    lk["wt_cross"] = float(wt_cross)
    lk["k_cross"] = int(k_cross)
    lk["mnn_floor"] = float(mnn_floor)
    lk["mutual"] = bool(mutual)
    return cfg


def _patch_dual_cross_stitch(
        cfg: dict,
        per_channel: bool = False,
        init_diag: float = 0.9,
        init_off: float = 0.1,
    ) -> dict:
    """
    Cross-stitch coupling (Misra et al., CVPR 2016): learn a 2x2 mix of
    the cell- and niche-branch post-MLP latents before the cell-VQ / GNN
    split. The "soft sharing" middle ground between the coupled shared
    trunk and the fully decoupled encoders — one cross-stitch unit spans
    the whole shared-to-split spectrum and learns the optimal mix from
    data, so there is no hand-picked split point.

    Operates on the DECOUPLED architecture: this patch ensures a
    separate niche MLP exists (adds one, a copy of the cell MLP, if the
    cfg doesn't already have it) and removes any Y-shape shared trunk,
    then attaches `cross_stitch_params` for the encoder to build a
    `CrossStitch` unit. `per_channel=False` -> one 2x2 (4 scalars);
    `per_channel=True` -> an independent 2x2 per feature channel.

    Apply OUTERMOST on a decoupled spine (e.g. s55_v3).
    """
    enc = cfg["model"]["encoder_params"]
    # Require / ensure the decoupled architecture (independent niche MLP).
    if enc.get("niche_mlp_params") is None:
        enc["niche_mlp_params"] = _copy(enc.get("mlp_params", {})) or {}
    enc.pop("shared_mlp_params", None)   # cross-stitch is incompatible with Y-shape
    enc["cross_stitch_params"] = {
        "per_channel": bool(per_channel),
        "init_diag": float(init_diag),
        "init_off": float(init_off),
    }
    return cfg


def _patch_dual_stopgrad_coupled(cfg: dict) -> dict:
    """
    Gradient-level coupling (stop-gradient; cf. Yu et al. 2020 family):
    keep ONE shared MLP trunk (coupled), but DETACH the niche-path input
    so spatial-loss gradients (adjacency BCE, nbr-NB, niche-commit) never
    flow back into the trunk that also produces the cell-VQ input. The
    trunk is then trained purely by the cell objective; the GNN, niche VQ
    and niche decoder still train on top of the detached trunk features.

    This is the cheapest way to protect the cell-intrinsic codes from
    spatial corruption while physically sharing the encoder — near-zero
    parameter overhead (a single `.detach()` in the forward pass).

    Forces the coupled trunk (removes any separate niche/shared MLP) and
    sets `detach_gnn_input=True`. Apply OUTERMOST on a spine.
    """
    enc = cfg["model"]["encoder_params"]
    enc.pop("niche_mlp_params", None)
    enc.pop("shared_mlp_params", None)
    enc.pop("cross_stitch_params", None)
    enc["detach_gnn_input"] = True
    return cfg


def _patch_dual_soft_coupling(cfg: dict, wt: float = 1e-3) -> dict:
    """
    Soft parameter sharing (Duong et al. 2015; Yang & Hospedales 2017):
    keep the two encoders fully DECOUPLED (independent cell + niche MLP
    trunks) but add an L2 penalty on the distance between their matched
    weight tensors, so the two trunks are encouraged to stay similar
    without physically sharing parameters. The lightest-touch coupling
    of the decoupled architecture.

    Ensures the decoupled architecture (adds a niche MLP copy if absent)
    and sets `loss_kwargs['wt_encoder_coupling'] = wt`; the dual model
    adds `wt * sum_l ||W_cell[l] - W_niche[l]||_F^2` to the total loss.
    `wt` is small by default because the penalty sums over all MLP
    weights (large absolute magnitude). Apply OUTERMOST on a decoupled
    spine (e.g. s55_v3).
    """
    enc = cfg["model"]["encoder_params"]
    if enc.get("niche_mlp_params") is None:
        enc["niche_mlp_params"] = _copy(enc.get("mlp_params", {})) or {}
    enc.pop("shared_mlp_params", None)
    enc.pop("cross_stitch_params", None)
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_encoder_coupling"] = float(wt)
    return cfg


def _patch_dual_compositional_cell_to_niche(
        cfg: dict,
        source: str = "z_q_cell",
        detach: bool = True,
        project_dim: Optional[int] = None,
    ) -> dict:
    """
    Compositional cell->niche coupling (idea #1): inject the cell branch's
    representation as extra node features for the niche GNN, so the GNN
    aggregates neighbours' cell identity (= local cell-type composition,
    CellCharter/Banksy-style). Directional, asymmetric: with `detach=True`
    (default) the injected signal carries NO gradient back to the cell branch,
    so the cell codes stay protected while the niche branch gets strictly more
    (biologically-relevant) information.

    `source`     : 'z_q_cell' (quantized = denoised identity, default) or
                   'z_mlp_cell' (continuous pre-VQ).
    `detach`     : protect the cell branch (default True).
    `project_dim`: optionally project the cell signal before concatenation
                   (None = full concat).

    Apply OUTERMOST on a decoupled spine (e.g. s55_v3).
    """
    enc = cfg["model"]["encoder_params"]
    enc["cell_to_niche"] = {
        "source": source,
        "detach": bool(detach),
        "project_dim": (int(project_dim) if project_dim else None),
    }
    return cfg


def _patch_dual_disentangle(cfg: dict, wt: float = 100.0) -> dict:
    """
    Disentanglement penalty (idea #2): add a Barlow-Twins-style
    cross-correlation decorrelation loss between the cell and niche latents,
    pushing the niche code to carry only signal complementary to the cell
    code. Adds `disentangle_cell_niche_loss` to loss_names and sets
    `loss_kwargs['wt_disentangle']`. The penalty is the mean squared
    cross-correlation (in [0, 1]), so `wt` plays the same upweighting role as
    the adjacency BCE weight. Apply OUTERMOST on any dual spine.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "disentangle_cell_niche_loss" not in losses:
        losses.append("disentangle_cell_niche_loss")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_disentangle"] = float(wt)
    return cfg


def _patch_dual_branch_adapter(
        cfg: dict,
        kind: str = "lora",
        rank: Optional[int] = None,
        hidden: Optional[int] = None,
    ) -> dict:
    """
    Parameter-efficient coupling: force the COUPLED (shared) trunk and add a
    small identity-initialized per-branch adapter (cell adapter before VQ_cell,
    niche adapter before the GNN). One shared trunk carries the expensive input
    layers; the tiny adapters give each branch its specialization — far fewer
    params than the two full trunks of the decoupled encoder.

    `kind`   : 'affine' (~2*dim params/branch), 'lora' (rank-r residual,
               ~2*r*dim), or 'mlp' (small residual head, ~2*dim*hidden).
    `rank`   : LoRA rank (lora only).
    `hidden` : hidden width (mlp only; defaults to dim).

    Apply OUTERMOST on a spine (e.g. s55_v3) — it removes any decoupled / Y-shape
    / cross-stitch / cell->niche encoder config so the trunk is genuinely shared.
    """
    enc = cfg["model"]["encoder_params"]
    enc.pop("niche_mlp_params", None)
    enc.pop("shared_mlp_params", None)
    enc.pop("cross_stitch_params", None)
    enc.pop("cell_to_niche", None)
    ad = {"kind": kind}
    if rank is not None:
        ad["rank"] = int(rank)
    if hidden is not None:
        ad["hidden"] = int(hidden)
    enc["branch_adapter"] = ad
    return cfg


def _build_s51_spine_codebook(cell_sizes, niche_sizes):
    """Build the s51_v1 / s49_v23 spine with the given per-branch RVQ codebook
    sizes. This is BYTE-IDENTICAL to the s52_v1 build chain (decoupled-enc +
    within-batch contrastive wt=10/k=5 + cell-VQ codebook-diversity wt=10 +
    decoder-cov + no-batch-int + enc-deeper [400,400,256] + dec-w[32] + knn16 +
    sampler[16] + gnn=1 + bs=512 + lr=7e-4 + within-sec), parametrised only by
    `cell_sizes` / `niche_sizes` (e.g. (10, 30)). Used for the L0 codebook-size
    ablation (s54_*) so every such variant is correct-by-construction and
    differs from the s51_v1 reference ONLY in the codebook size."""
    return _patch_dual_codebook_diversity(
        _patch_dual_contrastive_cell_within_batch(
            _patch_dual_adj_within_section_only(
                _patch_dual_no_batch_int(
                    _patch_dual_batch_lr(
                        _patch_dual_attr_recon_weight(
                            _patch_dual_sampler_neighbors(
                                _patch_dual_graph_knn(
                                    _patch_dual_decoder_width(
                                        _patch_dual_decoupled_encoders(
                                            _patch_dual_encoder_deeper(
                                                _patch_dual_decoder_covariate(
                                                    _patch_dual_rvq(
                                                        _patch_dual_rvq(_BD(),
                                                            branch="niche", codebook_sizes=niche_sizes,
                                                        ),
                                                        branch="cell", codebook_sizes=cell_sizes,
                                                    ),
                                                ),
                                                hidden_channels=[400, 400, 256],
                                            ),
                                        ),
                                        hidden_channels=[32],
                                    ),
                                    n_neighs=16,
                                ),
                                num_neighbors=[16],
                            ),
                            weight=1.0,
                        ),
                        batch_size=512, lr=7e-4,
                    ),
                ),
                enabled=True,
            ),
            wt_contrastive_cell=10.0, k_pos=5, temperature=0.1,
        ),
        weight=10.0, temperature=100.0, branch="cell",
    )


def _patch_dual_vq_warmup(cfg: dict, vq_warmup_epochs: int = 10) -> dict:
    """
    Defer codebook init + EMA updates for the first `vq_warmup_epochs`
    training epochs.

    Mechanism (see `VQNiche_Dual.on_train_epoch_start` and the
    `freeze_updates` buffer on `CosineSimCodebook` / `EuclideanCodebook`):
      - During warmup: lazy kmeans-init is held off, EMA updates are
        skipped, dead-code expiry is skipped. Commit losses are zeroed
        in `_step` (so the encoder isn't pulled toward arbitrary
        uniform-init codes).
      - At epoch `vq_warmup_epochs`: the next forward pass triggers
        natural kmeans-init on a z_mlp distribution that has been
        shaped by the reconstruction + integration losses, so the
        initial code centroids are much less batch-correlated than
        they would be at epoch 0.

    Hypothesis: the EMA update over batch-correlated early-epoch
    z_mlp locks some codes into "this batch only" territory; once
    that happens, the dead-code revival is the only way to recover,
    and it doesn't fire on codes that ARE active (just active on
    one batch). Warmup avoids this lock-in.

    Parameters
    ----------
    vq_warmup_epochs : int
        Number of epochs to freeze the codebook. Default 10. Set 0
        to disable (legacy behaviour).
    """
    cfg["model"]["vq_warmup_epochs"] = int(vq_warmup_epochs)
    return cfg


def _patch_dual_adj_within_section_only(cfg: dict, enabled: bool = True) -> dict:
    """
    Set `loss_kwargs['adj_within_section_only']` (default in code: True).

    When True, the BCE adjacency reconstruction loss only computes BCE
    over within-section pairs — cross-section pairs (which are negatives
    by construction, since spatial edges are intra-section) are dropped
    from the candidate-negative pool and from positive-weight accounting.
    This prevents the loss from pushing apart biologically-similar
    cells in different AnnData sections, an anti-integration pressure
    baked into the legacy global-pair behaviour.

    Use this helper to set the flag EXPLICITLY in a variant's
    materialised YAML even though True is the code default — useful for
    sweeps where you want the YAML to record the choice unambiguously
    next to the runs that explicitly chose `enabled=False`.

    See `bce_cosine_adjacency_reconstruction_loss` for the masking
    implementation details.
    """
    cfg["model"]["loss_params"]["loss_kwargs"]["adj_within_section_only"] = bool(enabled)
    return cfg


def _patch_dual_max_epochs(cfg: dict, max_epochs: int = 200) -> dict:
    """
    Override the training-budget cap (`trainer.max_epochs`).

    The base config uses `max_epochs=80` (see the long history comment
    inside `make_train_config_dualvq` near the `max_epochs` field for
    why — short version: the 2026-05-11 jump to 200 + patience=20 +
    val_loss monitor regressed niche NMI by ~0.03-0.05 across the
    board because the val_loss optimum drifted past the niche-NMI
    optimum).

    Use cases for bumping this:
      - Variants whose codebook hasn't visibly converged at epoch 80
        (rare but real for high-cardinality 3-level RVQ / large CVQ
        trees).
      - "Long-train better-Pareto?" probes — pair with
        `SQUINT_WITH_PEARSON=1` so the niche-quality-aware
        `val_pearson_gene_wise_1hop_nbr_log1p` monitor is available
        and verify post-hoc niche NMI before drawing conclusions.

    Note: this only RAISES the cap; the run can still early-stop earlier
    (patience=10 val passes ≈ 20 train epochs at the default
    check_val_every_n_epoch=2). To disable early stopping entirely,
    additionally set
    `cfg["trainer"]["early_stopping_params"]["enabled"] = False`.
    """
    cfg["trainer"]["max_epochs"] = int(max_epochs)
    return cfg


def _patch_dual_wide(
        cfg: dict,
        cell_codebook_size:  int = 50,
        niche_codebook_size: int = 50,
        gnn_layers:          int = 2,
        sampler_neighbors:   List[int] = [8, 8],
        nbr_hops:            int = 2,
    ) -> dict:
    """
    "Wide" variant of the dual model: bigger codebooks + deeper GNN +
    deeper sampler + multi-hop nbr aggregation. These knobs are coupled —
    if you bump the GNN depth without bumping the sampler depth, the GNN
    will see partial neighbourhoods and learn nonsense; if you bump the
    nbr-target aggregation without the sampler, the K-th-hop aggregate is
    approximate (computed on incomplete neighbour info). This patch sets
    them all together.

    Defaults (calibrated for ~100k cells / 50 niches):
      - cell VQ k=50          (was 30)
      - niche VQ k=50         (was 30)
      - GNN num_layers=2      (was 1) — niche encoder sees 2-hop context
      - sampler [8, 8]        (was [8]) — needed for the deeper GNN
      - nbr_aggregation_hops=2 — niche target is the 2-hop neighbourhood
                                 mean, encouraging codes to capture
                                 larger-scale spatial structure
    """
    enc = cfg["model"]["encoder_params"]
    enc["vq_cell_params"]["codebook_size"]  = int(cell_codebook_size)
    enc["vq_niche_params"]["codebook_size"] = int(niche_codebook_size)
    enc["gnn_params"]["num_layers"]         = int(gnn_layers)

    cfg["datamodule"]["sampler_params"]["num_neighbors"] = list(sampler_neighbors)

    cfg["model"]["loss_params"]["loss_kwargs"]["nbr_aggregation_hops"] = int(nbr_hops)
    return cfg


# ---------------------------------------------------------------------------
# Architecture ablations (mouse data)
# ---------------------------------------------------------------------------

def _patch_dual_scvi_compact(
        cfg: dict,
        encoder_hidden: int = 128,
        latent_dim:     int = 32,
        decoder_hidden: int = 128,
    ) -> dict:
    """
    Tight scVI-style architecture: 1 hidden layer per MLP + small
    latent dim. The whole geometry is collapsed onto `latent_dim`:

      - encoder MLP: hidden_channels = [encoder_hidden, latent_dim]
                    → 431 input → encoder_hidden hidden → latent_dim
                      output. 1 intermediate layer; output IS the
                      cell-VQ codebook input.
      - GNN:        SAGEConv, hidden_channels = latent_dim,
                      num_layers = 1 (stays at the dual-base default).
                      The niche-VQ codebook input.
      - cell decoder:  hidden_channels = [decoder_hidden]
                    → latent_dim (+ covariate) → decoder_hidden → 431
                      genes. 1 hidden layer; matches the encoder geometry
                      mirror-symmetrically.
      - niche decoder: same as cell decoder.

    Codebook embedding dim = latent_dim for BOTH branches (cell-VQ
    embedding dim = MLP output, niche-VQ embedding dim = GNN hidden).
    Compose with `_patch_dual_rvq(branch=..., codebook_sizes=...)` to
    set codebook geometry on top.

    Why bother:
      - At the SQUINT default (latent=256 + decoder [400, 400]) the
        decoder has room to absorb batch-specific patterns even with
        a `+decoder-cov` covariate, so the encoder doesn't NEED to
        produce batch-invariant z to keep reconstruction good. A
        tighter bottleneck (32) removes that escape hatch: there's
        no longer enough capacity for the decoder to memorise
        per-batch noise, so the encoder has to discard it. scVI's
        20-30 dim latent is the canonical example.
      - Smaller latent also means the cosine-distance VQ codebook
        operates in a lower-dim sphere, where the geometry is
        sharper and code assignment is less affected by random
        per-batch axes.

    Does NOT touch:
      - sampler_params (stays at the base default `[8]` since GNN
        depth stays at 1).
      - nbr_aggregation_hops (stays at 1 in the dual base).
      - decoder_covariate (compose `_patch_dual_decoder_covariate` on
        top — pass `embed_dim=latent_dim` for the symmetric variant
        the user prefers).
      - codebook sizes (compose `_patch_dual_rvq` on top).

    Parameters
    ----------
    encoder_hidden
        Width of the encoder MLP's hidden layer (default 128, like
        scVI's encoder).
    latent_dim
        Bottleneck dim (= MLP output = GNN hidden = codebook embedding).
        Default 32. scVI uses 10-30; 32 is a safe spatial-VQ analogue.
    decoder_hidden
        Width of the decoder MLP's hidden layer (default 128, mirrors
        the encoder).
    """
    enc = cfg["model"]["encoder_params"]
    enc["mlp_params"]["hidden_channels"]   = [int(encoder_hidden), int(latent_dim)]
    enc["gnn_params"]["hidden_channels"]   = int(latent_dim)
    # GNN num_layers stays at the dual-base default (=1) — caller
    # should compose `_patch_dual_gnn2` etc. on top if they want
    # 2-hop spatial context.
    for dec_key in ("attribute_decoder_cell_params",
                    "attribute_decoder_niche_params"):
        cfg["model"][dec_key]["mlp_params"]["hidden_channels"] = [int(decoder_hidden)]
    return cfg


def _patch_dual_small(cfg: dict, hidden: int = 128) -> dict:
    """
    scvi-style compact architecture: a single hidden layer of `hidden`
    dim (default 128) for the encoder MLP, the GNN, and both decoders.

    Configures:
      - encoder MLP:   hidden_channels = [hidden]   (was [400, 256])
      - GNN:           hidden_channels = hidden, num_layers = 1
      - cell decoder:  hidden_channels = [hidden]   (was [400, 400])
      - niche decoder: hidden_channels = [hidden]   (was [400, 400])

    Latent / codebook embedding dim becomes `hidden` (cell_dim and
    niche_dim both = `hidden`), so the codebook itself is also more
    compact. Codebook size is left untouched (still 30 by default; bump
    via `_patch_dual_rvq` etc. on top of this).

    Tests whether the smaller-is-better intuition that drives scvi
    transfers to spatial VQ-VAE. Parameter count drops ~5x vs the
    SQUINT default.
    """
    enc = cfg["model"]["encoder_params"]
    enc["mlp_params"]["hidden_channels"]  = [int(hidden)]
    enc["gnn_params"]["hidden_channels"]  = int(hidden)
    enc["gnn_params"]["num_layers"]       = 1
    for dec_key in ("attribute_decoder_cell_params",
                    "attribute_decoder_niche_params"):
        cfg["model"][dec_key]["mlp_params"]["hidden_channels"] = [int(hidden)]
    return cfg


def _patch_dual_gnn2(
        cfg: dict,
        sampler_neighbors: List[int] = [8, 8],
        nbr_aggregation_hops: int = 2,
    ) -> dict:
    """
    Bump GNN depth from 1 to 2 layers WITHOUT changing the codebook
    size (`_patch_dual_wide` couples both). Sampler depth and niche
    target aggregation hops move with it (otherwise the GNN samples
    nodes it won't aggregate over, or the nbr-target aggregation runs
    on incomplete neighbours — see `_patch_dual_wide` docstring).

    Use this as a clean isolation of "does deeper spatial context
    help?" — codebook stays at 30 (or whatever was set upstream),
    everything else as default.
    """
    cfg["model"]["encoder_params"]["gnn_params"]["num_layers"] = 2
    cfg["datamodule"]["sampler_params"]["num_neighbors"] = list(sampler_neighbors)
    cfg["model"]["loss_params"]["loss_kwargs"]["nbr_aggregation_hops"] = int(
        nbr_aggregation_hops
    )
    return cfg


def _patch_dual_decoder_width(
        cfg: dict,
        hidden_channels,
        branch: str = "both",
    ) -> dict:
    """
    Override the attribute-decoder MLP `hidden_channels` for the cell
    and/or niche branches independently.

    Defaults in the dual base: both decoders use `[400, 400]` (2
    hidden layers, gelu, layer_norm). Shrinking the decoder
    constrains the reconstruction pathway: less capacity for the
    decoder to absorb per-cell / per-batch gene patterns → more
    pressure on the latent / codebook to encode the reconstruction
    signal directly. Hypothesis: tighter decoder forces the encoder
    to produce more discriminative latents → potentially better
    NMI/iLISI at the cost of NB Pearson on hard genes.

    Parameters
    ----------
    hidden_channels
        Decoder hidden widths as a list of ints. Examples:
          - `[256, 256]` : 2 hidden layers, narrower than default
          - `[128, 128]` : 2 hidden layers, much narrower
          - `[64, 64]`   : 2 hidden layers, extreme bottleneck
          - `[400]`      : 1 hidden layer, baseline width (depth-only
                           reduction)
          - `[128]`      : 1 hidden layer, narrow
          - `[64]`       : 1 hidden layer, extreme bottleneck
        Last entry feeds the NB rate head (softmax × read_depth);
        the head itself is appended internally and isn't included
        in this list.
    branch
        "both" (default) | "cell" | "niche". Apply to cell decoder,
        niche decoder, or both independently. Asymmetric variants
        (e.g. tight niche decoder + baseline cell decoder) test
        whether the decoder pressure helps one branch more than
        the other.
    """
    target = list(hidden_channels)
    if branch in ("cell", "both"):
        cfg["model"]["attribute_decoder_cell_params"]["mlp_params"]["hidden_channels"] = target
    if branch in ("niche", "both"):
        cfg["model"]["attribute_decoder_niche_params"]["mlp_params"]["hidden_channels"] = target
    return cfg


def _patch_dual_small_latent(cfg: dict, latent_dim: int = 128) -> dict:
    """
    Shrink the latent / codebook-embedding dimension. Both `cell_dim`
    (= last layer of encoder MLP) and `niche_dim` (= GNN hidden) move
    to `latent_dim` (default 128, down from 256).

    Tighter bottleneck → fewer dimensions to spread information across,
    so each code's embedding has to be more semantically concentrated.
    NicheCompass / scvi typically use 10–32; 128 still leaves headroom
    while halving the SQUINT default.

    Decoder hidden widths and codebook size are unchanged.
    """
    enc = cfg["model"]["encoder_params"]
    h = list(enc["mlp_params"].get("hidden_channels", []))
    if len(h) == 0:
        # No MLP trunk — just set the GNN dim. The cell branch then
        # quantises raw input directly which is unusual; warn but
        # respect.
        print("WARN: _patch_dual_small_latent: no MLP trunk configured "
              "(mlp_params.hidden_channels is empty). Setting GNN hidden "
              "only — cell branch latent dim will equal in_channels.")
    else:
        h[-1] = int(latent_dim)
        enc["mlp_params"]["hidden_channels"] = h
    enc["gnn_params"]["hidden_channels"] = int(latent_dim)
    return cfg


def _patch_dual_dropout(cfg: dict, p: float = 0.1) -> dict:
    """
    Add dropout `p` (default 0.1) to encoder MLP, GNN, and both
    decoders. Cheap regularization — useful when val Pearson plateaus
    while train Pearson keeps climbing (a sign of overfitting). With
    val_loss-based early stopping, dropout's effect is monitorable
    directly in wandb.
    """
    enc = cfg["model"]["encoder_params"]
    enc["mlp_params"]["dropout"] = float(p)
    enc["gnn_params"]["dropout"] = float(p)
    for dec_key in ("attribute_decoder_cell_params",
                    "attribute_decoder_niche_params"):
        cfg["model"][dec_key]["mlp_params"]["dropout"] = float(p)
    return cfg


def _patch_dual_mlp_width(
        cfg: dict,
        encoder_hidden: List[int],
        decoder_hidden: List[int],
    ) -> dict:
    """
    Override the MLP hidden widths for BOTH the encoder trunk and the
    cell + niche attribute decoders. Useful for capacity ablations
    that want a coordinated change (encoder + decoder grow / shrink
    together) rather than a separate sweep on each side.

    The LAST element of `encoder_hidden` is the encoder MLP's output
    dim — i.e. the latent / codebook embedding dim. Pick it equal to
    the existing latent (typically 256) to isolate "hidden width"
    from "latent dim"; pick something else to ablate latent dim
    along with width.

    Decoders take only `decoder_hidden` (their output dim is fixed at
    n_genes by the model wiring).
    """
    enc = cfg["model"]["encoder_params"]
    enc["mlp_params"]["hidden_channels"] = list(encoder_hidden)
    for dec_key in ("attribute_decoder_cell_params",
                    "attribute_decoder_niche_params"):
        if dec_key in cfg["model"]:
            cfg["model"][dec_key]["mlp_params"]["hidden_channels"] = list(decoder_hidden)
    return cfg


def _patch_dual_encoder_deeper(
        cfg: dict,
        hidden_channels: Optional[List[int]] = None,
    ) -> dict:
    """
    Deepen the encoder MLP trunk: from `[400, 256]` (2 hidden layers)
    to `[400, 400, 256]` (3 hidden layers) by default. Latent dim
    (= last layer = 256) is preserved so codebook + GNN dims don't
    shift; only the depth grows. The extra layer adds ~160k params
    and a bit of FLOPs but lets the encoder learn richer non-linear
    feature mixes before quantisation.
    """
    enc = cfg["model"]["encoder_params"]
    target = list(hidden_channels) if hidden_channels else [400, 400, 256]
    enc["mlp_params"]["hidden_channels"] = target
    return cfg


def _patch_dual_gnn_hidden(
        cfg: dict,
        hidden: int = 384,
    ) -> dict:
    """
    Bump the niche-branch GNN hidden width (default 256 -> 384).
    Note: this changes the GNN's *internal* dim AND the niche latent
    dim (= GNN output) — codebook embedding dim follows. Larger spatial
    capacity at modest cost (~1.5x params on the GNN).
    """
    cfg["model"]["encoder_params"]["gnn_params"]["hidden_channels"] = int(hidden)
    return cfg


def _patch_dual_gnn_layers(
        cfg: dict,
        num_layers: int = 2,
    ) -> dict:
    """
    Override the niche-branch GNN depth (`gnn_params.num_layers`). Base
    default is 1 layer (= 1-hop aggregation). Setting `num_layers=2`
    gives 2-hop aggregation — the niche encoder sees neighbours of
    neighbours.

    IMPORTANT: the sampler depth MUST match the GNN depth, otherwise
    the second GNN layer sees incomplete neighbour sets and the
    aggregation is silently wrong. For `num_layers=2` on a knn=16
    graph, set the sampler to `[16, 16]` via
    `_patch_dual_sampler_neighbors(num_neighbors=[16, 16])`.

    This helper is a surgical "GNN-only" knob — it does NOT touch
    `nbr_aggregation_hops` (the niche-side reconstruction TARGET k-hop
    radius) or codebook sizes; for the coupled "everything wide"
    sweep see `_patch_dual_wide`. Keeping these orthogonal lets you
    ablate GNN depth without confounding it with target-aggregation
    radius or codebook capacity.

    Memory: each extra GNN layer adds ~D^2 params (default D=256 → 65k
    params/layer). Activation memory scales with the deeper sampler
    fan-out — `[16, 16]` is ~16x the per-step memory of `[16]`.
    """
    cfg["model"]["encoder_params"]["gnn_params"]["num_layers"] = int(num_layers)
    return cfg


def _patch_dual_sampler_neighbors(
        cfg: dict,
        num_neighbors: Optional[List[int]] = None,
    ) -> dict:
    """
    Override the `NeighborLoader.num_neighbors` per layer (default
    `[8]` for 1-hop). Increasing to `[16]` doubles the niche
    aggregation neighborhood, often improving spatial-domain coherence
    at the cost of larger per-step memory.
    """
    target = list(num_neighbors) if num_neighbors else [16]
    cfg["datamodule"]["sampler_params"]["num_neighbors"] = target
    return cfg


def _patch_dual_graph_knn(cfg: dict, n_neighs: int = 8) -> dict:
    """
    Select which pre-built spatial k-NN graph to use at training time.

    Sets `cfg["dataset"]["graph_params"]["n_neighs"]` — the loader
    then picks the corresponding `edge_index_*` from the dataset
    blob. This is a SELECTION at runtime, not a graph build: the
    target k MUST exist in the blob's `n_neighs_list` (set in
    `make_dataset_blob_config()`).

    To use k values not in the existing blob:
      1. Add the desired k(s) to `make_dataset_blob_config()`'s
         `graph_kwargs.n_neighs_list` (e.g. `[6, 8, 12]`).
      2. Rebuild the blob:  `python examples/run_squint.py --build-blob`
      3. Use this patch to select the new k at training time.

    Parameters
    ----------
    n_neighs : int
        Target spatial k-NN k value. Must be present in the blob's
        n_neighs_list. Smaller k → sparser graph → less spatial
        signal per cell + faster sampling. Larger k → richer
        spatial context but heavier per-step memory.
    """
    cfg["dataset"]["graph_params"]["n_neighs"] = int(n_neighs)
    return cfg


def _patch_dual_adversarial(
        cfg: dict,
        alpha: float = 1.0,
        wt_adv_batch: float = 150.0,
        hidden_channels: Optional[List[int]] = None,
        warmup_epochs: int = 0,
    ) -> dict:
    """
    Enable a domain-adversarial batch-invariance head on `z_mlp`.

    What it does: a small MLP classifier predicts the per-cell batch
    label from `z_mlp`. A Gradient Reversal Layer (GRL) is placed between
    the encoder and the classifier, so:
      - The classifier learns to predict batch (gets the true gradient).
      - The encoder is pushed AWAY from being batch-predictive (gets the
        negated gradient).

    The model classifies the FULL `z_mlp` (seeds + sampled GNN neighbours),
    not only the seed-node prefix — see VQNiche_Dual._step for the rationale.
    This makes the niche branch's GNN aggregate over batch-invariant inputs.

    Effect: provides the missing batch-invariance pressure on the latent
    that NicheCompass gets from its KL prior. Pair with
    `_patch_dual_decoder_covariate` for the full NicheCompass-shaped
    setup (decoder absorbs per-batch gene patterns, encoder is pushed
    to be batch-invariant).

    Parameters
    ----------
    alpha: float
        Strength of the gradient reversal (encoder pressure). Default 1.0
        — the standard Ganin-Lempitsky setting; multiplies the negated
        gradient that flows back to the encoder. Earlier we tried alpha
        =2.0 (with wt_adv_batch=100) and the codes started to collapse
        (encoder pressure too aggressive). Reverted to alpha=1.0 and
        bumped `wt_adv_batch` instead — the encoder gradient magnitude
        is `alpha * wt_adv_batch * d_CE/d_z`, so the two knobs are
        interchangeable for encoder pressure; the difference is that
        `wt_adv_batch` also accelerates the classifier (sharper
        adversary signal at the cost of faster CE→0 saturation).
    wt_adv_batch: float
        Weight of the CE loss in the total loss. Default 150.0. With 2
        batches the binary CE is bounded by log(2) ≈ 0.69 nats while
        the cell + niche NB losses sit at ~150 nats each; at
        `wt_adv_batch=1.0` the adversarial gradient is ~150x weaker
        than reconstruction and the encoder ignores it. 150.0 brings
        the encoder pressure to ~1.5x the "almost good" alpha=1, wt=100
        baseline without the codebook collapse seen at alpha=2. Sweep
        log-ish (100, 150, 200, 300) — the right value depends on
        dataset, codebook size, and how aggressive the decoder's batch-
        absorption pathway (concat / FiLM) already is.
    hidden_channels: list of int, optional
        Hidden widths for the classifier MLP. Default [128] (one
        hidden layer of 128 units).
    """
    cfg["model"]["adversarial_batch_dim_request"] = True
    cfg["model"]["adversarial_alpha"] = float(alpha)
    if hidden_channels is not None:
        cfg["model"]["adversarial_hidden_channels"] = list(hidden_channels)
    # `warmup_epochs` is wired through to VQNiche_Dual.__init__ and
    # consumed inside `_step`: during the first `warmup_epochs`
    # training epochs, the GRL is run with alpha=0 so the encoder
    # gets zero adversarial gradient (codes settle on biology first).
    # The classifier still trains and the CE term still appears in
    # total_loss for logging. Default 0 = legacy behaviour.
    cfg["model"]["adversarial_warmup_epochs"] = int(warmup_epochs)

    losses = cfg["model"]["loss_params"]["loss_names"]
    if "adversarial_batch_loss" not in losses:
        losses.append("adversarial_batch_loss")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_adv_batch"] = float(wt_adv_batch)
    return cfg


def _patch_dual_adversarial_cosine(
        cfg: dict,
        total_epochs: int = 100,
    ) -> dict:
    """
    Switch the adversarial alpha to a cosine schedule (vs the legacy
    constant). After warmup, alpha follows a half-sine envelope: rises
    from 0 at `warmup_epochs`, peaks at the midpoint of the post-warmup
    phase, decays back to ~0 at `total_epochs`. Past `total_epochs` the
    alpha stays at 0.

    Why use this: the constant schedule keeps adversarial pressure on
    the encoder until the very last epoch. Combined with `adv-warmup`,
    the cell token doesn't get a "consolidation phase" to refine
    cell-type-discriminative features without the gradient reversal
    pulling them apart. The cosine decay creates that consolidation
    phase in the final ~25% of training, while still giving strong
    integration pressure mid-training.

    Pair with `_patch_dual_adversarial(warmup_epochs=10, ...)` and an
    `adv-warmup10` variant tag for the intended use case.

    NOTE: requires `_patch_dual_adversarial` to have been called first
    on the cfg (this patch only flips the schedule flag — the
    adversarial head itself is built by the prior patch).
    """
    if "adversarial_batch_dim_request" not in cfg["model"]:
        raise RuntimeError(
            "_patch_dual_adversarial_cosine: call "
            "_patch_dual_adversarial() first to enable the adversarial "
            "head, then chain this patch on top."
        )
    cfg["model"]["adversarial_schedule"] = "cosine"
    cfg["model"]["adversarial_total_epochs"] = int(total_epochs)
    return cfg


def _patch_dual_adversarial_cell_only(cfg: dict) -> dict:
    """
    Restrict the adversarial classifier to the SEED prefix of z_mlp
    (i.e. the per-cell embedding before VQ), instead of classifying
    the full tensor (seeds + sampled neighbours).

    Why: the niche-branch GNN aggregates over neighbour z_mlp rows to
    produce z_gnn. With the legacy `apply_to='full'` setting, the
    adversarial gradient reaches BOTH the cell pathway (z_mlp[:B] -> VQ
    cell) and the niche pathway (z_mlp[B:] -> GNN -> VQ niche). Both
    branches lose batch-correlated info. With `apply_to='cell'`, only
    the seed rows feed the adversary's CE — the niche branch is left
    un-pressured by the adversary, keeping its spatial-aggregation
    capacity intact.

    Hypothesis: cell-type identification benefits from concentrating
    the adversarial "budget" on the cell branch where it matters most;
    the niche branch's batch-mixing is achieved instead by the
    decoder covariate + adjacency reconstruction (which already
    absorb batch-specific patterns elsewhere).

    NOTE: requires `_patch_dual_adversarial` to have been called first.
    """
    if "adversarial_batch_dim_request" not in cfg["model"]:
        raise RuntimeError(
            "_patch_dual_adversarial_cell_only: call "
            "_patch_dual_adversarial() first to enable the adversarial "
            "head, then chain this patch on top."
        )
    cfg["model"]["adversarial_apply_to"] = "cell"
    return cfg


def _patch_dual_mmd_batch(
        cfg: dict,
        wt_mmd_batch: float = 50.0,
        n_sub: int = 512,
    ) -> dict:
    """
    Add a non-adversarial MMD batch-invariance loss on the cell-token
    input (z_mlp[:batch_size]).

    Computes a kernel-based MMD between per-batch distributions on
    each mini-batch and adds it directly to the total loss. Unlike
    the adversarial CE — which involves a min-max game between the
    classifier and the encoder, and can fail to remove
    batch-correlated features that were learned during a warmup phase —
    MMD applies a deterministic distribution-matching pressure on
    every step.

    Recipe (mirrors `mmd_comparable` in compute_inference_metrics.py
    so train-time pressure and test-time evaluation use the same
    kernel):
      - z-score per-dim normalisation
      - RBF kernel with sigma chosen by median pairwise distance
      - Pairwise MMD^2 across all batches present, summed

    Use cases:
      1. Pair with `_patch_dual_adversarial(warmup_epochs=10)` to give
         a non-adversarial integration safety-net during the warmup
         period (during which the GRL alpha is 0).
      2. Replace the adversarial CE entirely (drop
         `_patch_dual_adversarial`) to test whether MMD alone is
         sufficient for batch alignment — simpler architecture, no
         classifier to tune.

    Parameters
    ----------
    wt_mmd_batch
        Loss weight for the MMD term. Default 50.0. The unweighted
        MMD^2 is in [0, 2] for a normalised kernel; values around
        50-200 put it on a comparable scale to the adversarial CE
        (which sits at log(2) * wt_adv_batch ≈ 100 for wt=150).
    n_sub
        Sub-sample size per batch. Default 512 — keeps the pairwise
        kernel matrix at ~1 MB.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "mmd_batch_loss" not in losses:
        losses.append("mmd_batch_loss")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_mmd_batch"] = float(wt_mmd_batch)
    cfg["model"]["loss_params"]["loss_kwargs"]["mmd_n_sub"] = int(n_sub)
    # The model's `_step` populates `mmd_target` and `mmd_target_labels`
    # from `z_mlp[:batch_size]` and `adata_batch_ids[:batch_size]`
    # unconditionally; the dispatcher only consumes them when
    # `mmd_batch_loss` is in `loss_names`.
    return cfg


def _patch_dual_mmd_prior(
        cfg: dict,
        wt_mmd_prior: float = 50.0,
        n_sub: int = 512,
        prior_std: float = 1.0,
    ) -> dict:
    """
    Add a non-adversarial, NON-PARAMETRIC MMD-to-prior loss.

    Pulls the empirical distribution of `z_mlp[:batch_size]` (the
    cell-token input pre-VQ) toward samples from the isotropic
    Gaussian prior `N(0, prior_std² * I)`. This is the parameterless
    analogue of NicheCompass's `KL(q(z|x) || N(0, I))` divergence —
    achieves the same prior-matching pressure without needing to
    make the encoder probabilistic (output mu, sigma) and without
    requiring KL annealing.

    Mechanism:
      - The prior is batch-agnostic by construction.
      - Pulling the embedding toward the prior forces per-batch z
        distributions to converge to the same prior → integrated.
      - Combined with `+decoder-cov` (which absorbs per-batch
        differences on the decoder side), this mirrors NicheCompass's
        integration without the adversarial min-max game OR the
        parametric VAE complexity.

    Compared to siblings:
      - `_patch_dual_adversarial`: min-max GRL game. Unstable
        dynamics, but strong gradient when working.
      - `_patch_dual_mmd_batch`: matches per-batch distributions to
        EACH OTHER (pairwise). Requires batch labels.
      - `_patch_dual_mmd_prior` (this): matches the empirical
        distribution to a FIXED prior. No batch labels. Single MMD
        per call.

    All three can coexist — they consume overlapping data but
    compute different distances.

    Use cases:
      1. Replace `+adv` entirely → pure prior-matching integration.
      2. Combine with `+adv` → stacked: GRL game + prior pull.
      3. Combine with `+mmd-w*` (batch MMD) → "match to each other
         AND to a prior".

    Parameters
    ----------
    wt_mmd_prior
        Loss weight on the MMD^2 vs prior. Default 50 (similar
        magnitude to `_patch_dual_mmd_batch`'s default).
    n_sub
        Sub-sample size for the pairwise kernel. Default 512.
    prior_std
        Std of the isotropic Gaussian prior. Default 1.0 (= N(0, I)).
        Bump up if the encoder's natural scale is large and the
        prior pull fights reconstruction too hard.
    """
    losses = cfg["model"]["loss_params"]["loss_names"]
    if "mmd_prior_loss" not in losses:
        losses.append("mmd_prior_loss")
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_mmd_prior"] = float(wt_mmd_prior)
    cfg["model"]["loss_params"]["loss_kwargs"]["mmd_n_sub"] = int(n_sub)
    cfg["model"]["loss_params"]["loss_kwargs"]["mmd_prior_std"] = float(prior_std)
    # The model's `_step` populates `mmd_target` from
    # `z_mlp[:batch_size]` unconditionally; this loss consumes the
    # same tensor as `mmd_batch_loss` but ignores `mmd_target_labels`
    # (no batch labels needed for prior-matching).
    return cfg


def _patch_dual_encoder_shallow(
        cfg: dict,
        hidden_channels: Optional[List[int]] = None,
    ) -> dict:
    """
    Shrink the encoder MLP trunk: from `[400, 256]` (2 hidden layers,
    the default) to `[256]` (1 hidden layer) by default. Latent dim
    (= last layer output = 256) is preserved so codebook + GNN dims
    don't shift; only the depth shrinks.

    Hypothesis: a smaller-capacity encoder has less room to memorise
    batch-specific features, which (combined with a brief warmup
    phase) may push the cell-type discriminative signal up while
    keeping the integration cost manageable. Sibling of
    `_patch_dual_encoder_deeper`; both target the same MLP trunk
    inside the encoder.

    NOTE: this is the trunk only — the GNN depth and decoder MLP
    width are controlled separately by `_patch_dual_wide` / the
    sampler patches / `_patch_dual_small`. For an even more
    aggressive capacity bottleneck, pair with `_patch_dual_small`.
    """
    enc = cfg["model"]["encoder_params"]
    target = list(hidden_channels) if hidden_channels else [256]
    enc["mlp_params"]["hidden_channels"] = target
    return cfg


def _patch_dual_commit_niche_weight(
        cfg: dict,
        wt_commit_niche: float = 2.0,
    ) -> dict:
    """
    Increase (or decrease) the niche-branch commit-loss weight. Default 1.0
    (set in `_make_default_dual_config`). Sibling of
    `_patch_dual_commit_cell_weight`; both can be applied in sequence
    via patch chaining (e.g. cell=3.0 + niche=0.5 to asymmetrically
    sharpen the cell side while loosening the niche side).

    The niche commit loss pulls `z_gnn[:batch_size]` (the niche-branch
    pre-VQ representation) toward `z_q_niche` (post-VQ). Higher weight
    → niche codes more concentrated → more distinct spatial regions
    per code. Lower weight → niche codes smear → finer-grained niche
    structure can survive in the residual.

    Use cases:
      - `wt_commit_niche > 1.0`: sharpen niche codes, often boosts
        Niche NMI on the composite RVQ code; risk of over-coarsening
        the spatial niches (multiple distinct regions collapse to one
        code).
      - `wt_commit_niche < 1.0`: looser niche commit, codes carry
        less variance — useful when the niche encoder seems to be
        overfitting batch-correlated spatial structure.
    """
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_commit_niche"] = float(wt_commit_niche)
    return cfg


def _patch_dual_commit_cell_weight(
        cfg: dict,
        wt_commit_cell: float = 2.0,
    ) -> dict:
    """
    Increase the cell-branch commit-loss weight from the default 1.0
    (set per-loss inside `_make_default_dual_config`) to `wt_commit_cell`.

    The commit loss pulls `z_mlp[:batch_size]` (the cell-branch input
    pre-VQ) toward `z_q_cell` (the post-VQ embedding). Higher weight
    means z_mlp commits more aggressively to discrete codes — codes
    are sharper / less smeared, and within-class variance in the
    cell-token shrinks.

    Hypothesis: with the cell-token discrete codes "sharpened", cells
    of the same cell-type cluster around fewer codes, raising the
    NMI(cell-token, cell_type). Trade-off: higher cell-commit can
    starve the niche-branch GNN, which consumes the SAME z_mlp tensor
    (sampled neighbours) — if z_mlp is dominated by sharp cell-cluster
    geometry, the GNN's spatial aggregation may degrade. Pair with
    a weaker niche-branch lever (e.g. lower wt_commit_niche) if you
    see niche-NMI regress.
    """
    cfg["model"]["loss_params"]["loss_kwargs"]["wt_commit_cell"] = float(wt_commit_cell)
    return cfg


# NOTE: `_patch_dual_cross_entropy` was removed on purpose.
#
# That patch enabled a supervised cross-entropy loss on the cell-type
# label, which would have turned SQUINT into a semi-supervised method
# (consuming ground-truth `cell_type` at training time). We're keeping
# SQUINT strictly unsupervised so it stays directly comparable to the
# unsupervised / zero-shot baselines (scVI, NicheCompass, BANKSY,
# Geneformer, scGPT, ...). The Linear predictor submodule itself is
# still built by BaseModel (256 -> n_cell_types) but its output is
# never folded into the loss, so it's harmless dead weight.
#
# If you ever need a supervised oracle / upper-bound number, do it as
# a one-off external experiment outside the published variant set —
# don't reintroduce a `+ce-w*` patch here.


def _patch_dual_decoder_film(
        cfg: dict,
        condition_list: List[str] = ["cell_batch_id"],
        init_mode: str = "small_random",
        small_random_std: float = 0.1,
    ) -> dict:
    """
    Enable FiLM batch-correction INSIDE the dual-model attribute decoders
    (cell + niche). Mutually exclusive with `_patch_dual_decoder_covariate`
    (which concatenates the one-hot onto z_q instead).

    What it does: sets `apply_conditioning='in-MLP'` on both decoder
    parameter dicts and configures their FiLM `condition_list` (default
    ['cell_batch_id'], i.e. per-cell batch one-hot). The data loader's
    `attr_decoder_conditions` tensor is then threaded through to each
    decoder by VQNiche_Dual.forward, and FiLM modulates each decoder
    layer with γ/β derived from the batch one-hot.

    Why init_mode defaults to 'small_random', not 'identity'
    --------------------------------------------------------
    Empirically, with `init_mode='identity'` the niche branch in this
    setup did NOT integrate well across platforms while `+decoder-cov`
    (concat) DID. The reason is the gradient signal at init:
      - 'identity' starts with γ=1, β=0 *constants* regardless of the
        batch one-hot. The decoder defaults to "ignore the batch info"
        and the path of least resistance is to encode batch in z_q
        instead of via FiLM. Gradient pressure to deviate from identity
        only kicks in if the codes ALREADY don't carry batch — which
        they do, because of the per-batch spatial graph.
      - 'small_random' starts with weights ~ N(0, std²) and identity
        bias, so γ ≈ 1 ± std and β ≈ 0 ± std *per channel per batch*
        from epoch 0. Different batches see different (small) γ/β
        perturbations → there is condition-dependent gradient signal
        from the very first step → the decoder readily learns to
        absorb per-batch shifts via FiLM, freeing the codes (same
        mechanism that makes concat work).
    Concat works for the same reason at the architectural level: the
    decoder's first linear layer initialises W_b with kaiming_uniform,
    so the batch one-hot already injects condition-dependent noise that
    the decoder is incentivised to replace with a meaningful per-batch
    bias. 'small_random' is the FiLM-side analog of that.

    `small_random_std=0.1` makes the per-channel perturbation magnitude
    on the order of the activation scale at init (10%) — comparable to
    a Kaiming-init linear layer's contribution from a one-hot input.
    """
    film_params = {
        "condition_list":    list(condition_list),
        "use_bias":          True,
        "use_residual":      False,
        "residual_weight":   0.2,
        "init_mode":         init_mode,
        "small_random_std":  float(small_random_std),
    }
    for dec_key in ("attribute_decoder_cell_params",
                    "attribute_decoder_niche_params"):
        cfg["model"][dec_key]["apply_conditioning"] = "in-MLP"
        cfg["model"][dec_key]["conditioning_params"] = film_params.copy()
    return cfg


def _patch_dual_decoder_covariate(
        cfg: dict,
        embed_dim: int = 16,
    ) -> dict:
    """
    Enable NicheCompass-style decoder covariate via a LEARNED batch
    embedding (concat-based batch correction).

    What it does: at runtime, `train()` sets `decoder_covariate_dim` to
    the number of distinct samples in the dataset (= n train batches).
    The dual model then learns an `nn.Embedding(n_batches, embed_dim)`
    and concatenates `embedding[adata_batch_ids]` (an `embed_dim`-dim
    learned vector per cell) onto z_q_cell and z_q_niche before each
    decoder. The decoders are constructed with extended `in_channels`
    by `embed_dim` (NOT by `n_batches` — the old one-hot scheme).

    Why a learned embedding instead of one-hot:
      - Generalises to NOVEL batches at inference. The mean of trained
        embeddings is a meaningful "neutral" covariate for held-out
        sections; one-hot has no valid index for unseen batches and
        forces an arbitrary "treat as if it were train batch 0"
        fallback. The dual model's forward path swaps in the mean
        embedding for cells flagged via `adata_batch_ids_unseen_mask`
        (set by `build_batch_one_hot_from_obs` when the cell's label
        wasn't in the train-time densification map).
      - Lower-dim conditional (default embed_dim=16 vs n_batches which
        can be 8-20+).
      - Encoder still doesn't see batch info → codes (= VQ output) are
        batch-invariant by construction; only the DECODER reconstruction
        depends on the embedding lookup.

    Effect:
      - Decoders use the learned batch embedding to fit per-batch
        gene patterns (different gene-capture rates, different noise
        structure across MERFISH/STARmap/CosMx).
      - Encoder is "freed" from encoding batch info in z_q because the
        decoder can absorb per-batch differences via the embedding.
      - Codebook (shared across batches) is biased toward batch-
        invariant biological identity.

    Parameters
    ----------
    embed_dim : int
        Dimensionality of the learned batch embedding. 16 is a good
        default — large enough to capture meaningful cross-batch
        differences, small enough to keep the decoder input compact.
    """
    cfg["model"]["decoder_covariate_dim_request"] = True
    cfg["model"]["decoder_covariate_embed_dim"]   = int(embed_dim)
    return cfg


def _patch_dual_decoupled_decoder_cov(cfg: dict) -> dict:
    """
    Split the decoder-covariate `nn.Embedding` into TWO independent
    modules — one per decoder. Each decoder's batch covariate then
    receives gradients from THAT decoder's reconstruction loss ONLY;
    no parameter is shared between the cell-NB pathway and the
    nbr-NB pathway downstream of the codebook.

    Why this matters under `+decoupled-enc`
    --------------------------------------
    Architectural gradient-isolation audit of the dual model under
    `+decoupled-enc` (`vqniche_dual_encoder.py` + `vqniche_dual.py`):

      Module                         Per-branch?  Shared?
      ─────────────────────────────  ───────────  ──────────
      mlp_module (cell trunk)        cell-only    no
      niche_mlp_module (niche trunk) niche-only   no
      vq_cell                        cell-only    no
      vq_niche                       niche-only   no
      gnn_module, niche_neck         niche-only   no
      attribute_decoder_cell         cell-only    no
      attribute_decoder_niche        niche-only   no
      encoder.conditioning_module    n/a          NOT BUILT (no `condition_list` in cfg by default)
      batch_embedding                BOTH         **YES (single nn.Embedding)**

    Without this patch the `batch_embedding`'s rows receive gradient
    updates from cell-NB AND nbr-NB on every step — the last remaining
    learnable parameter shared between the two branches. With this
    patch, that's gone too: `batch_embedding_cell` is updated by
    cell-NB only, `batch_embedding_niche` by nbr-NB only.

    Sizing
    ------
    Doubles the number of decoder-covariate parameters (was
    `n_batches × 16` floats, now `2 × n_batches × 16`). Negligible
    relative to the rest of the model.

    Requires
    --------
    Must be applied AFTER `_patch_dual_decoder_covariate` (which sets
    `decoder_covariate_dim_request=True`); the runtime resolves the
    actual `decoder_covariate_dim` from the dataloader. No-op if
    `+decoder-cov` isn't enabled — the model sees the flag but the
    `decoder_covariate_dim==0` branch skips embedding creation entirely.
    """
    cfg["model"]["decoupled_decoder_covariate"] = True
    return cfg


def _patch_dual_chl59_lung5(
        cfg: dict,
        train_batch_idx: Optional[List[int]] = None,
        test_batch_idx: Optional[List[int]] = None,
        batch_size: int = 128,
        edge_sampling_ratio: float = 1.0,
    ) -> dict:
    """
    Swap the dataset to /nfs/team361/sb75/DATASETS/silver/chl59-8b_1p (8
    CosMx Lung samples) and configure whole-section holdout via
    SpatialBatchSplit.

    Parameters
    ----------
    train_batch_idx, test_batch_idx:
        `adata_batch_id` values (= the integer parsed out of
        `uns['batch']`, e.g. `uns['batch']='batch6'` -> id=6), NOT
        alphabetical file positions in the silver dir. SpatialBatchSplit
        matches `data.adata_batch_id` against these lists, so they MUST
        be the actual ids.

        Translation to `cfg['dataset']['adata_batch_idx']` (which IS
        position-based, used by `initialize_databatch` to slice the
        dataset blob) is done at runtime in `train()` after the blob
        is loaded, by reading each section's actual `adata_batch_id`
        and inverting the id -> position mapping.

        Two buckets:
          - `train_batch_idx`: sections used for gradient updates.
                               OPTIONAL — when omitted (default), train()
                               picks every blob section that isn't in
                               test/val. The base config's 10% cell-level
                               split runs on these and provides the val
                               signal for early stopping +
                               best-checkpoint.
          - `test_batch_idx`:  whole sections held out ENTIRELY from
                               training (NOT loaded into the training
                               data graph). Evaluated post-hoc by
                               `predict()` + the inference metrics
                               pipeline. Default `None` = no test set.

    Memory: lowers `batch_size` to 128 (from the 256 default inherited
    from the mmb-smb config) and `edge_sampling_ratio` to 1.0 (from 2.0).
    The Lung sections are denser than the mouse-brain ones AND have a
    larger gene panel (~946 vs. 431), so per-step autograd memory is
    roughly 2x the mmb-smb cost at the same batch_size. Override via the
    kwargs if your GPU has more memory.
    """
    test_batch_idx = list(test_batch_idx) if test_batch_idx else []
    # train_batch_idx is OPTIONAL — leave the train_batches list empty
    # when not specified so train() defaults to "every blob section not
    # in test/val".
    train_batch_idx = list(train_batch_idx) if train_batch_idx else []

    cfg["dataset"]["dataset_name"]   = "chl59-8b_1p"
    cfg["dataset"]["dataset_tag"]    = "chl59-8b_1p"
    cfg["dataset"]["root_data_dir"]  = "/nfs/team361/sb75/DATASETS"
    # `adata_batch_idx` (positions) is filled in at runtime in `train()`
    # by translating `train_batches` (ids) via the loaded blob's
    # id-to-position mapping. We leave it as a placeholder here so the
    # variant config archives the user-intended ids rather than positions
    # baked under a particular id-derivation assumption.
    cfg["dataset"]["adata_batch_idx"] = []

    cfg["dataset"]["train_transform_params"] = {
        "region":         None,
        "train_batches":  list(train_batch_idx),
        "val_batches":    [],   # no whole-section val; cell-level split provides val
        # `test_batches` here is INFORMATIONAL — these sections aren't
        # in `adata_batch_idx` so the data graph never contains them and
        # `SpatialBatchSplit.forward` is never called on them at training
        # time. We stamp the ids anyway so `predict()` reads them from
        # the saved config and tags inference cells with
        # `data_split = "test"` for stratified post-hoc metrics.
        "test_batches":   test_batch_idx,
        "xy_key":         "xy_coordinates",
        # Cell-level 10% split provides the val signal during training.
        "train_val_cell_split":
            cfg["dataset"]["train_transform_params"].get("train_val_cell_split", 0.10),
        "cell_split_seed":
            cfg["dataset"]["train_transform_params"].get("cell_split_seed", 0),
    }

    # The Lung AnnDatas have `obs['batch']` populated with per-sample
    # labels; the batch-key flag tells the blob builder to read it.
    cfg["dataset"]["graph_params"]["batch_key"] = "batch"

    # Memory tuning for the larger Lung gene panel + denser sampling
    # (see docstring). Defaults are conservative for a 44 GiB GPU; bump
    # them on bigger cards.
    cfg["datamodule"]["loader_params"]["batch_size"] = int(batch_size)
    cfg["model"]["loss_params"]["loss_kwargs"]["edge_sampling_ratio"] = float(
        edge_sampling_ratio
    )

    # Validation runs on the held-out replicate(s); name the monitor
    # accordingly so checkpoints are saved on test-set Pearson.
    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


def _patch_dual_chl59_2b_1p(
        cfg: dict,
        train_batch_idx: Optional[List[int]] = None,
        test_batch_idx: Optional[List[int]] = None,
        batch_size: int = 512,
        edge_sampling_ratio: float = 1.0,
    ) -> dict:
    """
    Swap the dataset to /lustre/scratch126/cellgen/lotfollahi/DATASETS/silver/chl59-2b_1p
    (2-sample CosMx Lung subset). Sibling of `_patch_dual_chl59_lung5`
    but pointing at the 2-sample silver directory and defaulting to
    bs=512 (no per-section memory bottleneck at 2 samples vs 8).

    Parameters
    ----------
    train_batch_idx, test_batch_idx:
        Same semantics as in `_patch_dual_chl59_lung5` — `adata_batch_id`
        values, NOT positions. Empty lists default to "every blob
        section used for training, none held out". With only 2 sections
        in this dataset, leaving both empty trains on both.
    batch_size:
        Default 512 (matches the s49_v23 spine). The chl59-8b helper
        defaults to 128 due to the larger gene panel + denser sampling
        at 8 sections; with only 2 sections the per-step autograd memory
        is much lower, so 512 is fine on the standard 44 GiB cards.
    edge_sampling_ratio:
        Default 1.0 (matches chl59-8b setting).
    """
    test_batch_idx = list(test_batch_idx) if test_batch_idx else []
    train_batch_idx = list(train_batch_idx) if train_batch_idx else []

    cfg["dataset"]["dataset_name"]   = "chl59-2b_1p"
    cfg["dataset"]["dataset_tag"]    = "chl59-2b_1p"
    cfg["dataset"]["root_data_dir"]  = "/lustre/scratch126/cellgen/lotfollahi/DATASETS"
    cfg["dataset"]["adata_batch_idx"] = []

    cfg["dataset"]["train_transform_params"] = {
        "region":         None,
        "train_batches":  list(train_batch_idx),
        "val_batches":    [],
        "test_batches":   test_batch_idx,
        "xy_key":         "xy_coordinates",
        "train_val_cell_split":
            cfg["dataset"]["train_transform_params"].get("train_val_cell_split", 0.10),
        "cell_split_seed":
            cfg["dataset"]["train_transform_params"].get("cell_split_seed", 0),
    }

    cfg["dataset"]["graph_params"]["batch_key"] = "batch"

    cfg["datamodule"]["loader_params"]["batch_size"] = int(batch_size)
    cfg["model"]["loss_params"]["loss_kwargs"]["edge_sampling_ratio"] = float(
        edge_sampling_ratio
    )

    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


def _patch_dual_mmb20(
        cfg: dict,
        train_adata_ids: Optional[List[int]] = None,
        test_adata_ids: Optional[List[int]] = None,
        batch_size: int = 64,
        edge_sampling_ratio: float = 1.0,
        gnn_layers: int = 1,
        sampler_neighbors: List[int] = [8],
        nbr_aggregation_hops: int = 1,
    ) -> dict:
    """
    Swap the dataset to /lustre/.../silver/mmb0-1b_smb1-20b_1p_shared_genes
    (1 MERFISH + 20 STARmap, all reindexed to MERFISH's gene panel by
    examples/harmonize_mmb_smb20_panels.py) and configure whole-section
    holdout via SpatialBatchSplit.

    Parameters
    ----------
    train_adata_ids, test_adata_ids:
        `adata_batch_id` values (= the integer parsed out of `uns['batch']`
        that the harmonize script stamps from the filename), NOT
        positions in the sorted blob. STARmap sections are 1..20; MERFISH
        is 82. `SpatialBatchSplit` matches `data.adata_batch_id` against
        these lists, so they MUST be the actual ids — passing positions
        would silently produce no masks for any section and trigger a
        `KeyError: 'train_mask'` at the next collate step.

        Two buckets:
          - `train_adata_ids`: sections used for gradient updates. The
                               base config's 10% cell-level split runs
                               on these and provides the val signal for
                               early stopping + best-checkpoint
                               selection.
          - `test_adata_ids`:  sections held out ENTIRELY from training
                               (NOT loaded into the training data graph
                               at all — excluded from `adata_batch_idx`).
                               Evaluated post-hoc by `predict()` + the
                               inference metrics pipeline. Default
                               `None` = no test set.

        `cfg['dataset']['adata_batch_idx']` is position-based (used by
        `initialize_databatch` to slice the dataset blob); the
        translation from ids to positions happens at runtime in
        `train()` once the blob is loaded.

    batch_size, edge_sampling_ratio:
        Memory tuning. mmb20 stays on the 431-gene MERFISH panel so
        per-step activations are similar to mmb-smb, but it keeps
        ~19 sections worth of static `x` + edge_index on GPU (~2.5 GiB
        more than mmb-smb's 2 sections) before sampling starts. The
        edge sampling ratio caps the negative-sampling memory in the
        cosine adjacency loss.

    gnn_layers, sampler_neighbors, nbr_aggregation_hops:
        Niche-branch depth knobs that move TOGETHER. The mmb20 default
        narrows back to single-hop (gnn=1, sampler=[8], nbr_hops=1)
        instead of the `+wide` 2-hop stack. The big memory win is the
        sampler depth: `[8, 8]` worst-case expands 64 seeds → 64·(1+8+64)
        = 4,672 sampled nodes; `[8]` expands to 64·(1+8) = 576 — almost
        an order of magnitude smaller everywhere downstream (input `x`,
        MLP/GNN activations, decoder activations, NB loss intermediates,
        cosine-adjacency pairs). The cost is less spatial context per
        cell (1-hop instead of 2-hop niche), but that's NicheCompass's
        default and the integration question (cross-platform retrieval)
        doesn't fundamentally need 2-hop context.

        These three are coupled — narrowing one without the others is
        wasteful: a 2-hop sampler feeding a 1-hop GNN samples neighbors
        the GNN won't use; a 2-hop nbr-target aggregation on a 1-hop
        sampler is approximate (computed on incomplete neighbour info).

    Reads `obs['batch']` (also stamped by the harmonize script) for the
    per-cell batch one-hots used by the encoder/decoder batch correction
    (FiLM, decoder covariate, adversarial head).
    """
    test_adata_ids = list(test_adata_ids) if test_adata_ids else []
    # train_adata_ids is OPTIONAL — when omitted train() defaults to
    # every blob section not in test/val.
    train_adata_ids = list(train_adata_ids) if train_adata_ids else []

    cfg["dataset"]["dataset_name"]   = "mmb0-1b_smb1-20b_1p_shared_genes"
    cfg["dataset"]["dataset_tag"]    = "mmb0-1b_smb1-20b_1p"
    cfg["dataset"]["root_data_dir"]  = "/lustre/scratch126/cellgen/lotfollahi/DATASETS"
    # `adata_batch_idx` (positions) is resolved at runtime in `train()`
    # from `train_batches` (ids) via the loaded blob's id-to-position
    # mapping. Test sections are deliberately excluded — they never
    # enter the training data graph; `predict()` builds its own dataset
    # from the silver dir and CAN run inference on them post-hoc.
    cfg["dataset"]["adata_batch_idx"] = []

    cfg["dataset"]["train_transform_params"] = {
        "region":         None,
        "train_batches":  list(train_adata_ids),
        "val_batches":    [],   # no whole-section val; cell-level split provides val
        # `test_batches` here is INFORMATIONAL — these sections aren't
        # in `adata_batch_idx` so the data graph never contains them and
        # `SpatialBatchSplit.forward` is never called on them at training
        # time. We stamp the ids anyway so `predict()` reads them from
        # the saved config and tags inference cells with
        # `data_split = "test"` for stratified post-hoc metrics.
        "test_batches":   test_adata_ids,
        "xy_key":         "xy_coordinates",
        # Cell-level 10% split provides the val signal during training.
        "train_val_cell_split":
            cfg["dataset"]["train_transform_params"].get("train_val_cell_split", 0.10),
        "cell_split_seed":
            cfg["dataset"]["train_transform_params"].get("cell_split_seed", 0),
    }

    cfg["dataset"]["graph_params"]["batch_key"] = "batch"

    # Memory tuning (see docstring). Defaults are conservative for a
    # 44 GiB GPU; bump them on bigger cards.
    cfg["datamodule"]["loader_params"]["batch_size"] = int(batch_size)
    cfg["model"]["loss_params"]["loss_kwargs"]["edge_sampling_ratio"] = float(
        edge_sampling_ratio
    )

    # Niche-branch depth (GNN / sampler / nbr-target aggregation move
    # together — see docstring). These OVERRIDE whatever `_patch_dual_wide`
    # set upstream, since this patch is applied last in the variant chain.
    cfg["model"]["encoder_params"]["gnn_params"]["num_layers"] = int(gnn_layers)
    cfg["datamodule"]["sampler_params"]["num_neighbors"] = list(sampler_neighbors)
    cfg["model"]["loss_params"]["loss_kwargs"]["nbr_aggregation_hops"] = int(
        nbr_aggregation_hops
    )

    # Validation runs on the held-out section(s); name the monitor
    # accordingly so checkpoints are saved on test-set Pearson.
    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


def _patch_dual_spatch_subset(
        cfg: dict,
        dataset_name: str,
        train_batch_idx: Optional[List[int]] = None,
        test_batch_idx=None,
        batch_size: int = 512,
        edge_sampling_ratio: float = 1.0,
    ) -> dict:
    """
    Generic dataset-switch helper for the spatch tissue-specific subsets
    (spatch_ov_1p, spatch_hcc_1p, spatch_coad_1p). Mirrors
    `_patch_dual_spatch` exactly but takes `dataset_name` as an argument
    so the same chain works across the 3 subsets.

    Defaults differ from the original `_patch_dual_spatch` smoke-test
    helper:
      - `batch_size=512` (matches the s51 spine; the smoke-test default
        of 16 was for fast iteration on a tiny GPU).
      - `train_batch_idx=None` -> "every blob section not in test/val"
        (i.e. train on ALL sections in the subset). The smoke-test
        defaulted to `[2]` because it wanted a single training
        section for fast iteration.

    Parameters
    ----------
    dataset_name : str
        One of "spatch_ov_1p", "spatch_hcc_1p", "spatch_coad_1p". Sets
        `cfg.dataset.dataset_name`, `dataset_tag`, and the artifact path.
    train_batch_idx, test_batch_idx
        Section-ID lists. Same semantics as `_patch_dual_spatch`. Both
        default to empty/unset, which `train()` resolves to "all
        sections for training, none held out". Pass an explicit list
        to do whole-section holdout.
    batch_size, edge_sampling_ratio
        Memory tuning; defaults match the s51 spine.
    """
    train_batch_idx = list(train_batch_idx) if train_batch_idx else []
    if test_batch_idx is None:
        test_batch_idx = []
    if isinstance(test_batch_idx, str):
        if test_batch_idx != "rest":
            raise ValueError(
                f"test_batch_idx string must be 'rest'; got {test_batch_idx!r}."
            )
    else:
        test_batch_idx = list(test_batch_idx)

    cfg["dataset"]["dataset_name"]   = dataset_name
    cfg["dataset"]["dataset_tag"]    = dataset_name
    cfg["dataset"]["root_data_dir"]  = "/nfs/team361/sb75/DATASETS"
    cfg["dataset"]["adata_batch_idx"] = []

    cfg["dataset"]["train_transform_params"] = {
        "region":         None,
        "train_batches":  list(train_batch_idx),
        "val_batches":    [],
        "test_batches":   test_batch_idx,
        "xy_key":         "xy_coordinates",
        "train_val_cell_split":
            cfg["dataset"]["train_transform_params"].get("train_val_cell_split", 0.10),
        "cell_split_seed":
            cfg["dataset"]["train_transform_params"].get("cell_split_seed", 0),
    }

    cfg["dataset"]["graph_params"]["batch_key"] = "batch"

    cfg["datamodule"]["loader_params"]["batch_size"] = int(batch_size)
    cfg["model"]["loss_params"]["loss_kwargs"]["edge_sampling_ratio"] = float(
        edge_sampling_ratio
    )

    cfg["trainer"]["monitor"] = "val_loss"
    return cfg


def _patch_dual_spatch_ov(
        cfg: dict,
        train_batch_idx: Optional[List[int]] = None,
        test_batch_idx=None,
        batch_size: int = 512,
        edge_sampling_ratio: float = 1.0,
    ) -> dict:
    """Thin wrapper: spatch_ov_1p (ovarian cancer subset)."""
    return _patch_dual_spatch_subset(
        cfg, dataset_name="spatch_ov_1p",
        train_batch_idx=train_batch_idx,
        test_batch_idx=test_batch_idx,
        batch_size=batch_size,
        edge_sampling_ratio=edge_sampling_ratio,
    )


