# ---------------------------------------------------------------------------
# Per-dataset ablation sweep matrix (10 variants per dataset).
# ---------------------------------------------------------------------------
# A consistent 10-axis ablation sweep registered for each of the 3 datasets.
# Run one dataset's sweep per HPC job (one per node) via:
#
#   python examples/run_squint.py --all-dataset mmb0-1b_smb1-1b_1p
#   python examples/run_squint.py --all-dataset chl59-8b_1p
#   python examples/run_squint.py --all-dataset mmb0-1b_smb1-20b_1p
#
# Each variant ablates ONE axis from a fixed spine baseline. The spine is:
#   wide (or narrow on memory-constrained datasets) + RVQ on both branches
#   (k1=30, k2=90) + NicheCompass-style decoder covariate (concat per-cell
#   batch one-hot) + adversarial GRL on FULL z_mlp (alpha=1.0, wt=150).
#
# For wide-spine datasets the 10 axes are:
#   1. baseline       — pure spine
#   2. gatv2          — SAGEConv -> GATv2Conv
#   3. small          — scvi-style hidden=128 everywhere (replaces wide)
#   4. small-latent   — latent / codebook-embedding dim 256 -> 128
#   5. dropout        — p=0.1 on encoder MLP, GNN, both decoders
#   6. dec-film       — FiLM-in-decoder INSTEAD of decoder covariate concat
#   7. no-adv         — drop the adversarial head
#   8. no-arch        — drop +wide (1-hop GNN, default codebook)
#   9. no-rvq         — single VQ k=30 on both branches (no RVQ)
#  10. no-adj         — drop the cosine adjacency BCE loss
#
# For the narrow (memory-constrained) mmb20 dataset, axis 8 changes from
# 'no-arch' to 'codebook-large' (RVQ levels 50/150 instead of 30/90),
# because a wider GNN OOMs at 19 sections on a 44 GiB GPU.

_SWEEP_AXES_WIDE = [
    "baseline", "gatv2", "small", "small-latent", "dropout",
    "dec-film", "no-adv", "no-arch", "no-rvq", "no-adj",
]
_SWEEP_AXES_NARROW = [
    "baseline", "gatv2", "small", "small-latent", "dropout",
    "dec-film", "no-adv", "codebook-large", "no-rvq", "no-adj",
]

_SWEEP_AXIS_DESC = {
    "baseline": (
        "Spine baseline (no ablation). Wide-or-narrow GNN + RVQ on both "
        "branches (k1=30, k2=90) + NicheCompass-style decoder covariate "
        "(concat per-cell batch one-hot) + adversarial GRL on FULL z_mlp "
        "(alpha=1.0, wt_adv_batch=150). Reference point for the 10-axis "
        "sweep."
    ),
    "gatv2": (
        "Spine + SAGEConv -> GATv2Conv on the niche-branch GNN. Tests "
        "per-edge attention vs. uniform mean aggregation. Helps more on "
        "sparse / heterogeneous neighbourhoods."
    ),
    "small": (
        "scvi-style compact architecture: 1 hidden layer of 128 dim "
        "everywhere (encoder MLP, GNN, both decoders). Latent / codebook "
        "embedding dim = 128. ~5x fewer parameters than the SQUINT default. "
        "Replaces +wide (which sets 2-layer GNN at 256 dim). RVQ + "
        "decoder-cov + adv unchanged. Tests whether smaller-is-better "
        "transfers to spatial VQ-VAE."
    ),
    "small-latent": (
        "Spine + latent / codebook-embedding dim 256 -> 128. Encoder MLP "
        "first layer stays at 400; only the last hidden layer + GNN hidden "
        "shrink. Tests whether forcing more semantically-concentrated "
        "codebook embeddings helps."
    ),
    "dropout": (
        "Spine + dropout p=0.1 on encoder MLP, GNN, and both decoders. "
        "Cheap regularization. Useful diagnostic when val Pearson plateaus "
        "while train Pearson keeps climbing."
    ),
    "dec-film": (
        "Spine but FiLM batch-correction INSIDE the cell + niche decoders "
        "(`apply_conditioning='in-MLP'`, condition=cell_batch_id) INSTEAD "
        "of concat-based decoder covariate. FiLM gives the decoder a "
        "per-layer modulation surface; recommended over concat for the "
        "deeper non-linear MLPSoftmax decoders."
    ),
    "no-adv": (
        "Spine WITHOUT the adversarial head. Decoder still gets the "
        "covariate. Tests whether the GRL is contributing batch invariance "
        "beyond what concat covariate alone achieves."
    ),
    "no-arch": (
        "Spine WITHOUT +wide (so 1-hop GNN, sampler=[8], nbr_hops=1, "
        "default codebook size). Tests whether the deeper spatial context "
        "from +wide is load-bearing once RVQ is in place."
    ),
    "no-rvq": (
        "Spine WITHOUT RVQ — single VQ at k=30 on both branches instead "
        "of residual (30, 90). Tests whether the hierarchical RVQ "
        "structure helps over a flat codebook of comparable budget."
    ),
    "no-adj": (
        "Spine WITHOUT the cosine adjacency BCE loss. Niche branch is "
        "supervised only by neighbourhood NB. Tests whether the "
        "adjacency term is load-bearing for spatial code coherence."
    ),
    "codebook-large": (
        "Spine but RVQ levels 30,90 -> 50,150 on both branches (larger "
        "primary + larger residual codebooks). Single coupled "
        "codebook-capacity scan; substituted for +wide on narrow "
        "(memory-constrained) datasets where a 2-hop GNN OOMs."
    ),
}


def _compose_sweep_spine(ablation: str, narrow: bool = False) -> dict:
    """
    Build the dual-VQ spine for the per-dataset ablation sweep, ablating
    exactly one axis. See the SWEEP_AXES tables for the axis catalogue.

    The dataset wrapper (e.g. _patch_dual_chl59_lung5,
    _patch_dual_mmb20_holdout) is applied AFTER this returns — those
    patches are not the responsibility of this function.
    """
    cfg = _BD()

    # Architecture (wide vs. narrow vs. small).
    if ablation == "small":
        # 'small' replaces both +wide AND the default-1-hop GNN (it sets
        # num_layers=1, hidden=128 directly). On narrow datasets the
        # dataset patch later re-asserts num_layers=1 (no conflict).
        cfg = _patch_dual_small(cfg)
    elif ablation == "no-arch":
        # No architectural patch: defaults to 1-hop GNN, default codebook.
        pass
    elif not narrow:
        cfg = _patch_dual_wide(cfg)
    # narrow + non-small: defer GNN config to the dataset wrapper (e.g.
    # _patch_dual_mmb20 sets num_layers=1, sampler=[8], nbr_hops=1).

    # VQ structure.
    if ablation == "no-rvq":
        # Single VQ at base k=30 on both branches — no RVQ wrap.
        pass
    elif ablation == "codebook-large":
        cfg = _patch_dual_rvq(cfg, branch="niche", codebook_sizes=(50, 150))
        cfg = _patch_dual_rvq(cfg, branch="cell",  codebook_sizes=(50, 150))
    else:
        cfg = _patch_dual_rvq(cfg, branch="niche", codebook_sizes=(30, 90))
        cfg = _patch_dual_rvq(cfg, branch="cell",  codebook_sizes=(30, 90))

    # Latent dim shrink.
    if ablation == "small-latent":
        cfg = _patch_dual_small_latent(cfg, latent_dim=128)

    # Dropout.
    if ablation == "dropout":
        cfg = _patch_dual_dropout(cfg, p=0.1)

    # GNN type.
    if ablation == "gatv2":
        cfg = _patch_dual_gatv2(cfg)

    # Decoder batch correction shape.
    if ablation == "dec-film":
        cfg = _patch_dual_decoder_film(cfg)
    else:
        cfg = _patch_dual_decoder_covariate(cfg)

    # Adversarial head.
    if ablation != "no-adv":
        cfg = _patch_dual_adversarial(cfg, alpha=1.0, wt_adv_batch=150.0)

    # Adjacency.
    if ablation == "no-adj":
        cfg = _patch_dual_no_adj(cfg)

    return cfg


def _sweep_variant_name(ablation: str, dataset_tag: str, narrow: bool) -> str:
    """Compose a descriptive variant name for the sweep matrix."""
    arch = "narrow" if narrow else "wide"
    if ablation == "baseline":
        core = f"{arch}+rvq-both+decoder-cov+adv"
    elif ablation == "gatv2":
        core = f"{arch}+rvq-both+decoder-cov+adv+gatv2"
    elif ablation == "small":
        # 'small' overrides architecture; prefix narrow-dataset names with
        # 'narrow+' so the dataset context stays visible.
        core = f"{'narrow+' if narrow else ''}small+rvq-both+decoder-cov+adv"
    elif ablation == "small-latent":
        core = f"{arch}+rvq-both+decoder-cov+adv+small-latent"
    elif ablation == "dropout":
        core = f"{arch}+rvq-both+decoder-cov+adv+dropout"
    elif ablation == "dec-film":
        core = f"{arch}+rvq-both+dec-film+adv"
    elif ablation == "no-adv":
        core = f"{arch}+rvq-both+decoder-cov"
    elif ablation == "no-arch":
        core = f"rvq-both+decoder-cov+adv"
    elif ablation == "no-rvq":
        core = f"{arch}+decoder-cov+adv"
    elif ablation == "no-adj":
        core = f"{arch}+rvq-both+decoder-cov+adv+no-adj"
    elif ablation == "codebook-large":
        core = f"{arch}+rvq-both-large+decoder-cov+adv"
    else:
        raise ValueError(f"unknown sweep ablation: {ablation!r}")
    return f"dualvq+{core}+{dataset_tag}"


def _sweep_patch_tags(ablation: str, narrow: bool) -> list[str]:
    """Patch-tag list for the variant's `patches` field (display only)."""
    arch_tag = "+narrow" if narrow else "+wide"
    rvq_tag = "+rvq(branch=both, levels=[30, 90])"
    base = [arch_tag, rvq_tag, "+decoder_covariate",
            "+adversarial_batch(alpha=1.0, wt=150.0)"]
    if ablation == "baseline":              return list(base)
    if ablation == "gatv2":                 return list(base) + ["+gatv2"]
    if ablation == "small":
        return ["+small(hidden=128 — encoder MLP + GNN + both decoders)", rvq_tag, "+decoder_covariate",
                "+adversarial_batch(alpha=1.0, wt=150.0)"]
    if ablation == "small-latent":          return list(base) + ["+small-latent(latent_dim=128)"]
    if ablation == "dropout":               return list(base) + ["+dropout(p=0.1)"]
    if ablation == "dec-film":
        return [arch_tag, rvq_tag, "+dec-film(in-MLP, cell_batch_id)",
                "+adversarial_batch(alpha=1.0, wt=150.0)"]
    if ablation == "no-adv":                return [arch_tag, rvq_tag, "+decoder_covariate"]
    if ablation == "no-arch":               return [rvq_tag, "+decoder_covariate",
                                                   "+adversarial_batch(alpha=1.0, wt=150.0)"]
    if ablation == "no-rvq":                return [arch_tag, "+decoder_covariate",
                                                   "+adversarial_batch(alpha=1.0, wt=150.0)"]
    if ablation == "no-adj":                return list(base) + ["-cosine_adj"]
    if ablation == "codebook-large":
        return [arch_tag, "+rvq(branch=both, levels=[50, 150])",
                "+decoder_covariate", "+adversarial_batch(alpha=1.0, wt=150.0)"]
    raise ValueError(f"unknown sweep ablation: {ablation!r}")


def _register_dataset_sweep(
        dataset_tag: str,
        dataset_apply_fn,
        narrow: bool = False,
    ) -> list[str]:
    """
    Register the 10-axis sweep variants for a dataset under VARIANTS.

    Idempotent: if a variant with the composed name already exists in
    VARIANTS (e.g. user-curated entries higher up in this file), the
    existing entry is kept and only the name is appended to the returned
    list. This lets the sweep matrix coexist with the hand-written
    variants without clobbering them.

    Returns the ordered list of variant names — used by run_dataset_pipeline.
    """
    axes = _SWEEP_AXES_NARROW if narrow else _SWEEP_AXES_WIDE
    names: list[str] = []
    for ablation in axes:
        name = _sweep_variant_name(ablation, dataset_tag, narrow)
        if name not in VARIANTS:
            # Bind ablation+narrow into closures so each variant builds its own.
            def _build(_a=ablation, _n=narrow, _apply=dataset_apply_fn):
                return _apply(_compose_sweep_spine(_a, narrow=_n))
            VARIANTS[name] = {
                "description": (
                    _SWEEP_AXIS_DESC[ablation]
                    + f" Dataset: {dataset_tag}."
                ),
                "patches": _sweep_patch_tags(ablation, narrow)
                           + [f"+{dataset_tag}"],
                "build": _build,
            }
        names.append(name)
    return names


# ===========================================================================
# s56 — ENCODER CELL/NICHE COUPLING-METHOD ablation (on the cross-batch MNN
# spine). How should the cell-intrinsic and spatial-niche encoders SHARE
# parameters so they "work well together" without spatial losses corrupting
# the cell codes? We sweep a spectrum from full sharing to full decoupling,
# plus three learned/elegant coupling methods drawn from the multi-task
# literature (Misra 2016 cross-stitch; Duong 2015 / Yang & Hospedales 2017
# soft sharing; Yu 2020-style stop-gradient). All built on the s55_v3
# cross-batch-MNN spine, so they're directly comparable to the rest.
#
# Endpoints already defined/run:
#   * DECOUPLED (reference) = s55_v3   (two independent MLP trunks)
#   * COUPLED               = s56_v1   (one shared MLP trunk)
# Partial sharing (Y-shape: shared trunk + per-branch heads, concat back to
# 256-d so codebook/decoder shapes are unchanged):
#   * s56_v2  shared 192 / path 64  (mostly shared)
#   * s56_v3  shared 128 / path 128 (balanced)
#   * s56_v4  shared 64  / path 192 (mostly specialised)
# Learned / elegant coupling:
#   * s56_v5  cross-stitch, one 2x2 mix (4 scalars; Misra 2016)
#   * s56_v6  cross-stitch, per-channel 2x2 (Misra 2016)
#   * s56_v7  stop-gradient on a coupled trunk (gradient-level coupling)
#   * s56_v8  soft parameter-sharing L2 penalty between decoupled trunks
# ===========================================================================
_S56_SPINE_KEY = ("s55_v3_dualvq+rvq-both+decoder-cov+no-batch-int+enc-deeper"
                  "+dec-w32+knn16+sampler16+cell-w1+bs512+lr7e-4+within-sec"
                  "+decoupled-enc+diversity-w10+contrastWB-w10-k5"
                  "+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p")


def _s56_spine():
    """Fresh build of the s55_v3 cross-batch-MNN spine (decoupled encoders),
    rebuilt each call so the coupling patches mutate an independent cfg."""
    return VARIANTS[_S56_SPINE_KEY]["build"]()


VARIANTS["s56_v1_coupled-enc+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
    "description": (
        "s56 coupling ablation on the CROSS-BATCH MNN spine: COUPLED encoder "
        "(cell + niche share ONE MLP trunk; hard parameter sharing) vs the "
        "decoupled default (s55_v3). Built by wrapping the s55_v3 build with "
        "_patch_dual_coupled_encoders, which removes the separate niche-side MLP "
        "(niche_mlp_params) so spatial-loss gradients flow back into the cell-VQ "
        "input. Everything else (cross-batch MNN wt_cross=10/k_cross=1, codebooks, "
        "graph, losses) is identical to s55_v3. Reference (decoupled) = s55_v3. "
        "Reuses the mmb0-1b_smb1-1b_1p blob (k=16)."
    ),
    "patches": ["= s55_v3 (cross-batch spine) + decoupled -> COUPLED encoder"],
    "build": lambda: _patch_dual_coupled_encoders(_s56_spine()),
}

# ---- Partial sharing: Y-shape (shared trunk + per-branch heads) ------------
# `_patch_dual_shared_specific_encoders` builds 3 MLPs (shared + cell-path +
# niche-path) and concatenates [shared, path] for each branch. We vary the
# split point via shared_last_dim / path_last_dim so the concatenated dim
# stays 256 (= the s55_v3 trunk output), keeping codebook + decoder shapes
# unchanged. Higher shared_last_dim = more sharing (closer to s56_v1 coupled);
# higher path_last_dim = more specialisation (closer to s55_v3 decoupled).
_S56_YSHAPE = [
    ("v2", "yshape-shared192-path64",  192, 64,  "mostly shared"),
    ("v3", "yshape-shared128-path128", 128, 128, "balanced"),
    ("v4", "yshape-shared64-path192",  64,  192, "mostly specialised"),
]
for _v, _tag, _sd, _pd, _desc in _S56_YSHAPE:
    VARIANTS[f"s56_{_v}_{_tag}+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
        "description": (
            f"s56 coupling ablation (cross-batch MNN spine): partial sharing via "
            f"the Y-shape encoder ({_desc}) — a shared MLP trunk (last dim {_sd}) "
            f"plus per-branch path MLPs (last dim {_pd}), concatenated to "
            f"{_sd + _pd}-d for each branch (= the s55_v3 trunk width, so codebook "
            f"and decoder shapes are unchanged). The shared trunk sees gradients "
            f"from BOTH branches; each path MLP sees only its own branch. "
            f"wt_cross=10/k_cross=1 cross-batch MNN as default. Reference = s55_v3."
        ),
        "patches": [
            f"= s55_v3 spine + Y-shape encoder (shared_last={_sd}, path_last={_pd})",
        ],
        "build": (lambda sd=_sd, pd=_pd: _patch_dual_shared_specific_encoders(
            _s56_spine(), shared_last_dim=sd, path_last_dim=pd)),
    }

# ---- Learned coupling: cross-stitch (Misra et al., CVPR 2016) --------------
VARIANTS["s56_v5_crossstitch-scalar+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
    "description": (
        "s56 coupling ablation (cross-batch MNN spine): CROSS-STITCH coupling "
        "(Misra et al. 2016) with ONE learnable 2x2 mixing matrix (4 scalars) "
        "shared across all channels, mixing the cell- and niche-branch post-MLP "
        "latents before the cell-VQ / GNN split. Spans the shared-to-decoupled "
        "spectrum and learns the optimal mix from data; near-identity init "
        "(0.9 / 0.1). Built on the decoupled s55_v3 spine. Reference = s55_v3."
    ),
    "patches": ["= s55_v3 spine + cross-stitch (per_channel=False)"],
    "build": lambda: _patch_dual_cross_stitch(_s56_spine(), per_channel=False),
}
VARIANTS["s56_v6_crossstitch-perchannel+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
    "description": (
        "s56 coupling ablation (cross-batch MNN spine): CROSS-STITCH coupling "
        "(Misra et al. 2016) with an INDEPENDENT 2x2 mix per feature channel "
        "(4 x dim scalars) — the per-unit form closest to the original paper. "
        "More expressive than the scalar variant (s56_v5). Built on the decoupled "
        "s55_v3 spine. Reference = s55_v3."
    ),
    "patches": ["= s55_v3 spine + cross-stitch (per_channel=True)"],
    "build": lambda: _patch_dual_cross_stitch(_s56_spine(), per_channel=True),
}

# ---- Gradient-level coupling: stop-gradient on a coupled trunk -------------
VARIANTS["s56_v7_stopgrad-coupled+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
    "description": (
        "s56 coupling ablation (cross-batch MNN spine): STOP-GRADIENT coupling. "
        "One physical shared MLP trunk (coupled), but the niche-path input is "
        "detached so spatial-loss gradients never reach the trunk that produces "
        "the cell-VQ input — the trunk is trained purely by the cell objective, "
        "while the GNN / niche VQ / niche decoder learn on top of the detached "
        "features. Cheapest cell-code protection while physically sharing the "
        "encoder (one .detach()). Reference = s55_v3 (decoupled), contrast vs "
        "s56_v1 (coupled, no detach)."
    ),
    "patches": ["= s55_v3 spine + COUPLED trunk + detach_gnn_input=True"],
    "build": lambda: _patch_dual_stopgrad_coupled(_s56_spine()),
}

# ---- Soft parameter sharing: L2 penalty between decoupled trunks -----------
VARIANTS["s56_v8_softcouple-w1e-3+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
    "description": (
        "s56 coupling ablation (cross-batch MNN spine): SOFT parameter sharing "
        "(Duong 2015 / Yang & Hospedales 2017). Two fully decoupled cell + niche "
        "MLP trunks (as in s55_v3) PLUS an L2 penalty on the distance between "
        "their matched weights (wt_encoder_coupling=1e-3), encouraging the trunks "
        "to stay similar without physically sharing parameters — the lightest-touch "
        "coupling. NOTE: the penalty sums over all MLP weights, so the 1e-3 weight "
        "is a starting point that may need tuning. Reference = s55_v3."
    ),
    "patches": ["= s55_v3 spine (decoupled) + wt_encoder_coupling=1e-3"],
    "build": lambda: _patch_dual_soft_coupling(_s56_spine(), wt=1e-3),
}


# ===========================================================================
# s57 — ALL ablations re-run on the CROSS-BATCH MNN contrastive spine.
# The s57 "default" contrastive loss is the cross-batch MNN variant
# (wt_cross=10, k_cross=1 == the s55_v3 config), replacing the within-batch
# contrastive used by the s51/s52/s54 ablations. Each s57 variant is generated
# by wrapping the corresponding within-batch ablation variant's build with
# _patch_dual_contrastive_cross_batch (swaps within-batch -> cross-batch MNN),
# so it stays in sync with the source variants.
#
# NOT generated (reused as-is):
#   * cross-batch reference (s49_v23 + cross)  = s55_v3 (already defined)
#   * contrastive-axis comparators             = s51_v1 (within) + s51_v2 (none)
#   * coupled/decoupled axis                   = s55_v3 (decoupled) + s56_v1 (coupled)
# ===========================================================================
_S57_CROSS = dict(wt_cross=10.0, k_cross=1)
# (s57 key tag, source-variant key PREFIX) — source resolved to its full mmb key.
_S57_SPEC = [
    ("no-adj",           "s51_v3_"),    # adjacency reconstruction: drop
    ("no-dec-cov",       "s51_v4_"),    # decoder covariate: drop
    ("gnn-l2",           "s51_v11_"),   # GNN depth: 2 layers
    ("knn8",             "s51_v8_"),    # neighbours: knn8 / sampler8
    ("knn16-sampler8",   "s51_v9_"),    # neighbours: knn16 / sampler8
    ("knn24",            "s51_v10_"),   # neighbours: knn24
    ("rvq-cell-30-10",   "s51_v6_"),    # cell codebook L1=10
    ("rvq-cell-30-30",   "s51_v5_"),    # cell codebook L1=30
    ("rvq-cell-30-300",  "s51_v7_"),    # cell codebook L1=300
    ("rvq-niche-30-10",  "s52_v1_"),    # niche codebook L1=10
    ("rvq-niche-30-30",  "s52_v2_"),    # niche codebook L1=30
    ("rvq-niche-30-300", "s52_v3_"),    # niche codebook L1=300
    ("rvq-cell-10-30",   "s54_v1_"),    # cell codebook L0=10
    ("rvq-cell-90-30",   "s54_v2_"),    # cell codebook L0=90
    ("rvq-cell-300-30",  "s54_v3_"),    # cell codebook L0=300
    ("rvq-niche-10-30",  "s54_v4_"),    # niche codebook L0=10
    ("rvq-niche-90-30",  "s54_v5_"),    # niche codebook L0=90
    ("rvq-niche-300-30", "s54_v6_"),    # niche codebook L0=300
]


def _s57_resolve_source(prefix):
    cands = [k for k in VARIANTS
             if k.startswith(prefix) and k.endswith("+mmb0-1b_smb1-1b_1p")]
    if len(cands) != 1:
        print(f"[s57] WARNING: prefix {prefix!r} matched {len(cands)} variant(s) "
              f"{cands}; skipping that s57 entry.")
        return None
    return cands[0]


for _i, (_tag, _pref) in enumerate(_S57_SPEC, start=1):
    _src = _s57_resolve_source(_pref)
    if _src is None:
        continue
    _key = f"s57_v{_i}_crossmnn-wt10-k1+{_tag}+mmb0-1b_smb1-1b_1p"
    VARIANTS[_key] = {
        "description": (
            f"s57 ablation on the CROSS-BATCH MNN contrastive spine (default = "
            f"cross-batch MNN wt_cross=10, k_cross=1, == s55_v3). This variant = "
            f"source '{_src}' with the within-batch contrastive loss swapped for "
            f"the cross-batch MNN loss (wraps the source build with "
            f"_patch_dual_contrastive_cross_batch). Reuses the mmb0-1b_smb1-1b_1p "
            f"blob (k=16). s57 reference = s55_v3; contrastive axis reuses "
            f"s51_v1 (within) / s51_v2 (none)."
        ),
        "patches": [
            f"= {_pref}<src> + within-batch contrastive -> cross-batch MNN "
            f"(wt_cross=10, k_cross=1)",
        ],
        "build": (lambda src=_src: _patch_dual_contrastive_cross_batch(
            VARIANTS[src]["build"](), **_S57_CROSS)),
    }


# ===========================================================================
# s58 — INFORMATION-FLOW / COMPLEMENTARITY coupling (beyond trunk-sharing).
# The s56 trunk-sharing sweep tied with the decoupled baseline -> sharing the
# trunk is not the lever. s58 instead changes WHAT flows between the branches:
#   #1 COMPOSITIONAL cell->niche coupling: the niche GNN consumes neighbours'
#      cell codes (detached) so the niche code is built on local cell-type
#      composition — directional, asymmetric (cell stays protected).
#   #2 DISENTANGLEMENT penalty: decorrelate the cell & niche latents so the
#      niche code captures only complementary signal.
#   plus #1+#2 combined.
# All on the s55_v3 cross-batch-MNN decoupled spine (_s56_spine()).
# Reference = s55_v3.
# ===========================================================================
VARIANTS["s58_v1_compose-cell2niche-zqcell+crossmnn-wt10-k1+mmb0-1b_smb1-1b_1p"] = {
    "description": (
        "s58 #1 compositional cell->niche coupling (cross-batch MNN spine): the "
        "niche GNN consumes neighbours' QUANTIZED cell codes (z_q_cell, detached) "
        "as extra node features, so the niche representation is built on local "
        "cell-type composition while the cell branch stays gradient-protected. "
        "Full concat (no projection). Reference = s55_v3 (decoupled)."
    ),
    "patches": ["= s55_v3 spine + cell_to_niche(source=z_q_cell, detach=True)"],
    "build": lambda: _patch_dual_compositional_cell_to_niche(
        _s56_spine(), source="z_q_cell", detach=True),
}
